  const [referentNames, setReferentNames] = useState<string[]>([]);
  const [coordinatorEmail, setCoordinatorEmail] = useState<string>('');
  const [authorEmail, setAuthorEmail] = useState<string>('');
  const [loading, setLoading] = useState(true);
  const [comment, setComment] = useState('');
  const [actionLoading, setActionLoading] = useState(false);
  const [syncing, setSyncing] = useState(false);

  // --- GUARDIAS DE SEGURIDAD CONTRA DUPLICIDAD ---
  const isProcessing = useRef(false);
  const lastExecutionTime = useRef(0);

  const [showResponseModal, setShowResponseModal] = useState(false);
  const [pendingAction, setPendingAction] = useState<'APPROVE' | 'REJECT' | null>(null);
  const [responseFile, setResponseFile] = useState<File | null>(null);
  const [fileError, setFileError] = useState<string[]>([]);
  const [isFileValid, setIsFileValid] = useState(false);
  const [detectedVersion, setDetectedVersion] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [showDeleteModal, setShowDeleteModal] = useState(false);

  // Estado para detectar si hay una versión más nueva
  const [latestDocInfo, setLatestDocInfo] = useState<{ id: string, version: string } | null>(null);

  useEffect(() => {
    if (location.state?.docData) {
        const passedDoc = location.state.docData;
        setDoc(passedDoc);
        if (!passedDoc.id.startsWith('virtual-')) {
             loadAuxiliaryData(passedDoc.id, passedDoc);
        } else {
             setLoading(false);
             if (passedDoc.assignees && passedDoc.assignees.length > 0) {
                 UserService.getAll().then(users => {
                     const names = passedDoc.assignees.map((aid: string) => users.find(u => u.id === aid)?.name).filter((n: string | undefined) => n) as string[];
                     setAssigneeNames(names);
                 });
             }
        }
    } else if (id && !id.startsWith('virtual-')) {
        loadData(id);
    } else {
        setLoading(false);
    }
  }, [id, location.state]);

  const loadAuxiliaryData = async (docId: string, currentDoc: Document) => {
      try {
          const relatedIds = await DocumentService.getRelatedDocIds(
              currentDoc.project!, 
              currentDoc.microprocess || currentDoc.title.split(' - ')[0], 
              currentDoc.docType!
          );

          const [h, allUsers, hierarchy, allReferents, allDocs] = await Promise.all([
              HistoryService.getHistory(relatedIds),
              UserService.getAll(),
              HierarchyService.getFullHierarchy(),
              ReferentService.getAll(),
              DocumentService.getAll()
          ]);

          setHistory(h);

          // Detectar si este documento es el más reciente de su grupo
          const relatedDocs = allDocs.filter(d => relatedIds.includes(d.id));
          if (relatedDocs.length > 1) {
              const latest = [...relatedDocs].sort((a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime())[0];
              if (latest && latest.id !== currentDoc.id) {
                  setLatestDocInfo({ id: latest.id, version: latest.version });
              } else {
                  setLatestDocInfo(null);
              }
          } else {
              setLatestDocInfo(null);
          }

          const coordinator = allUsers.find(u => ['COORDINATOR', 'COORDINADOR', 'ADMIN'].includes((u.role || '').toString().toUpperCase()));
          if (coordinator) setCoordinatorEmail(coordinator.email);
          const author = allUsers.find(u => u.id === currentDoc.authorId);
          if (author) setAuthorEmail(author.email);

          const matrix = resolveMatrixData(currentDoc, hierarchy, allReferents);
          setReferentEmails(matrix.referentEmails);
          setReferentNames(matrix.referentNames);

          if (matrix.assignees.length > 0) {
              const names = matrix.assignees.map(aid => allUsers.find(u => u.id === aid)?.name).filter(n => n) as string[];
              setAssigneeNames(names);
              const emails = matrix.assignees.map(aid => allUsers.find(u => u.id === aid)?.email).filter(e => e) as string[];
              setAssigneeEmails(emails);
          }
          setLoading(false);
      } catch (e) {
          console.error("Error loading aux data", e);
          setLoading(false);
      }
  };

  const resolveMatrixData = (d: Document, hierarchy: FullHierarchy, allReferents: Referent[]) => {
      let resolvedAssigneeIds = d.assignees || [];
      let resolvedReferentEmails: string[] = [];
      let resolvedReferentNames: string[] = [];

      if (d.project && d.microprocess) {
           const targetMicro = normalizeHeader(d.microprocess);
           const targetProject = normalizeHeader(d.project);
           let node: any = null;
           for (const projKey of Object.keys(hierarchy)) {
               if (normalizeHeader(projKey) === targetProject) {
                   for (const macroKey of Object.keys(hierarchy[projKey])) {
                       for (const procKey of Object.keys(hierarchy[projKey][macroKey])) {
                           const found = hierarchy[projKey][macroKey][procKey].find(n => normalizeHeader(n.name) === targetMicro);
                           if (found) { node = found; break; }
                       }
                       if (node) break;
                   }
               }
               if (node) break;
           }
           if (node?.assignees && (resolvedAssigneeIds.length === 0 || d.authorName.includes('Sistema'))) resolvedAssigneeIds = node.assignees;
           if (node?.referentIds && node.referentIds.length > 0) {
               const matches = allReferents.filter(r => node.referentIds.includes(r.id));
               resolvedReferentEmails = matches.map(r => r.email);
               resolvedReferentNames = matches.map(r => r.name);
           }
      }
      return { assignees: resolvedAssigneeIds, referentEmails: resolvedReferentEmails, referentNames: resolvedReferentNames };
  };

  const loadData = async (docId: string) => {
    setLoading(true);
    try {
        const d = await DocumentService.getById(docId);
        if (d) {
            setDoc(d);
            await loadAuxiliaryData(docId, d);
        } else {
            setDoc(null);
            setLoading(false);
        }
    } catch (error) {
        console.error("Error loading document data:", error);
        setDoc(null);
        setLoading(false);
    }
  };

  const handleSyncState = async () => {
      if (!doc || syncing) return;
      setSyncing(true);
      try {
          await DocumentService.syncMetadata(doc.id, user);
          await loadData(doc.id);
      } catch (e: any) {
          alert("Error al sincronizar: " + e.message);
      } finally {
          setSyncing(false);
      }
  };

  const getDocLink = () => `${window.location.origin}/#/doc/${doc?.id}`;

  const handleNotifyAnalyst = () => {
      if (!doc || assigneeEmails.length === 0) {
          alert("No hay correos de analistas definidos para este proceso.");
          return;
      }
      const displayVersion = formatVersionForDisplay(doc.version);
      const subject = encodeURIComponent(`Respuesta Solicitud: ${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${displayVersion}`);
      const body = encodeURIComponent(`Estimada/o,\nAdjunto el Informe: ${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${displayVersion}\n\nEstado Actual: ${STATE_CONFIG[doc.state].label}\n\nPuede revisar el detalle y los comentarios en: ${getDocLink()}\n\nSaludos\n${user.name}`);
      window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${encodeURIComponent(assigneeEmails.join(','))}&su=${subject}&body=${body}`, '_blank');
  };

  const handleNotifyReferent = () => {
      if (!doc || referentEmails.length === 0) {
          alert("No hay correos de referentes vinculados a este proceso en la matriz.");
          return;
      }
      const displayVersion = formatVersionForDisplay(doc.version);
      const subject = encodeURIComponent(`Revisión Técnica: ${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${displayVersion}`);
      const greeting = referentNames.length > 0 ? `Estimada/o ${referentNames.join(', ')}` : 'Estimados Referentes';
      const body = encodeURIComponent(`${greeting},\n\nSe solicita su validación para el documento: ${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${displayVersion}\n\nQuedamos atentos a sus observaciones.\n\nSaludos\n${user.name}`);
      window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${encodeURIComponent(referentEmails.join(','))}&su=${subject}&body=${body}`, '_blank');
  };

  const handleNotifyCoordinator = () => {
    if (!doc || !coordinatorEmail) { alert(`Aviso: No se ha detectado correo del coordinador.`); return; }
    const displayVersion = formatVersionForDisplay(doc.version);
    const subject = encodeURIComponent(`Solicitud de Revisión: ${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${displayVersion}`);
    const body = encodeURIComponent(`Estimado,\nPara su revisión, he cargado el documento "${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${displayVersion}",\n\nLink: ${getDocLink()}\n\nSaludos\n${user.name}`);
    window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${coordinatorEmail}&su=${subject}&body=${body}`, '_blank');
  };

  const handleActionClick = async (action: 'ADVANCE' | 'APPROVE' | 'REJECT' | 'COMMENT', e?: React.MouseEvent) => {
      if (e) { e.preventDefault(); e.stopPropagation(); }

      const now = Date.now();
      if (now - lastExecutionTime.current < 3000) return;

      if (!doc || isProcessing.current) return;
      isProcessing.current = true;
      lastExecutionTime.current = now;

      if (action === 'COMMENT') {
          const currentComment = comment.trim();
          if (!currentComment) { 
              alert('Escribe una observación.'); 
              isProcessing.current = false; 
              return; 
          }

          setActionLoading(true);
          setComment(''); 

          try {
              await DocumentService.transitionState(doc.id, user, 'COMMENT', currentComment);
              await loadData(doc.id);
          } catch (err: any) {
              alert('Error al guardar: ' + err.message);
              setComment(currentComment);
          } finally {
              isProcessing.current = false;
              setActionLoading(false);
          }
          return;
      }

      if (action === 'ADVANCE') { 
          setActionLoading(true);
          try {
              await DocumentService.transitionState(doc.id, user, 'ADVANCE', 'Gestión de flujo.');
              await loadData(doc.id);
          } finally {
              isProcessing.current = false;
              setActionLoading(false);
          }
          return; 
      }

      if (action === 'APPROVE' || action === 'REJECT') {
          if (action === 'REJECT' && !comment) { 
              alert('Agrega una observación para el rechazo.'); 
              isProcessing.current = false; 
              return; 
          }
          setPendingAction(action); setResponseFile(null); setFileError([]); setIsFileValid(false); setDetectedVersion(''); setShowResponseModal(true);
          isProcessing.current = false; 
      }
  };

  const handleResponseFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0] && doc && pendingAction) {
          const f = e.target.files[0]; setResponseFile(f);
          const result = parseDocumentFilename(f.name, doc.project, doc.microprocess, doc.docType);
          if (!result.valido) { setFileError(result.errores); setIsFileValid(false); return; }
          const rules = validateCoordinatorRules(f.name, doc.version, doc.state, pendingAction);
          if (!rules.valid) { setFileError([rules.error || 'Error de validación.']); setIsFileValid(false); return; }
          setIsFileValid(true); setFileError([]); setDetectedVersion(result.nomenclatura || '');
      }
  };

  const handleSubmitResponse = async (e: React.MouseEvent) => {
      e.preventDefault(); e.stopPropagation();

      const now = Date.now();
      if (now - lastExecutionTime.current < 3000) return;
      if (!doc || !pendingAction || !responseFile || !isFileValid || isProcessing.current) return;

      isProcessing.current = true;
      lastExecutionTime.current = now;
      setActionLoading(true);
      setShowResponseModal(false); 

      try {
        await DocumentService.transitionState(
            doc.id, 
            user, 
            pendingAction, 
            comment || `Gestión realizada.`, 
            responseFile, 
            detectedVersion
        );
        setComment('');
        await loadData(doc.id);
      } catch(err: any) {
          alert('Error: ' + err.message);
      } finally {
        isProcessing.current = false;
        setActionLoading(false);
      }
  };

  const handleRevertAction = async () => {
      if (!doc || isProcessing.current) return;
      setShowDeleteModal(false);

      isProcessing.current = true;
      setLoading(true);

      try {
          const wasDeleted = await DocumentService.revertLastTransition(doc.id);
          if (wasDeleted) {
              navigate('/', { replace: true });
          } else {
              await loadData(doc.id);
          }
      } catch (e: any) {
          alert("Error al revertir: " + e.message);
          setLoading(false);
      } finally {
          isProcessing.current = false;
      }
  };

  const handleNewRequestPrefilled = () => {
      if (!doc) return;
      navigate('/new', { 
          state: { 
              prefill: { 
                  project: doc.project, 
                  macro: doc.macroprocess, 
                  process: doc.process, 
                  micro: doc.microprocess, 
                  docType: doc.docType 
              } 
          } 
      });
  };

  const formatDate = (isoString: string) => {
    const date = new Date(isoString);
    if (isNaN(date.getTime())) return 'Fecha no disponible';
    return date.toLocaleString('es-CL', { 
        day: '2-digit', month: '2-digit', year: 'numeric', 
        hour: '2-digit', minute: '2-digit', second: '2-digit',
        hour12: true 
    });
  };

  if (loading && !doc) return <div className="p-8 text-center text-slate-500 flex flex-col items-center"><RefreshCw size={24} className="animate-spin mb-2" />Cargando documento...</div>;
  if (!doc) return <div className="p-12 text-center text-slate-500">No se encontró el documento.</div>;

  const config = STATE_CONFIG[doc.state];
  const isAssignee = doc.assignees && doc.assignees.includes(user.id);
  const isAuthor = doc.authorId === user.id;
  const isAnalystAssigned = user.role === UserRole.ANALYST && (isAssignee || isAuthor);
  const isCoordinatorOrAdmin = user.role === UserRole.COORDINATOR || user.role === UserRole.ADMIN;
  const canEdit = isAnalystAssigned || isCoordinatorOrAdmin;
  const isDocActive = doc.state !== DocState.APPROVED;

  // NUEVA LÓGICA DE DETECCIÓN DE INCONSISTENCIA (INCLUYE PENDING STATUS)
  const expectedInfo = determineStateFromVersion(doc.version);
  const expectedState = expectedInfo.state;
  const expectedPending = [
      DocState.INTERNAL_REVIEW, 
      DocState.SENT_TO_REFERENT, 
      DocState.REFERENT_REVIEW, 
      DocState.SENT_TO_CONTROL, 
      DocState.CONTROL_REVIEW
  ].includes(expectedState);

  const isInconsistent = !doc.id.startsWith('virtual-') && (doc.state !== expectedState || doc.hasPendingRequest !== expectedPending);

  const canReview = isCoordinatorOrAdmin && [DocState.INTERNAL_REVIEW, DocState.REFERENT_REVIEW, DocState.CONTROL_REVIEW, DocState.SENT_TO_REFERENT, DocState.SENT_TO_CONTROL].includes(doc.state);

  return (
    <div className="max-w-6xl mx-auto space-y-6 pb-12">
      <div className="flex justify-between items-center">
        <button onClick={() => navigate(-1)} className="flex items-center text-slate-500 hover:text-slate-800 text-sm font-medium transition-colors">
            <ArrowLeft size={16} className="mr-1" /> Volver
        </button>
        <div className="flex items-center gap-2">
            {user.role === UserRole.ADMIN && !doc.id.startsWith('virtual-') && (
                <button type="button" onClick={() => setShowDeleteModal(true)} disabled={actionLoading} className="flex items-center text-red-500 hover:text-red-700 text-[11px] font-bold uppercase tracking-wider px-3 py-1.5 bg-red-50 hover:bg-red-100 rounded-lg border border-red-100 transition-colors shadow-sm disabled:opacity-50">
                    <Trash2 size={14} className="mr-1.5" /> Eliminar
                </button>
            )}
        </div>
      </div>

      {/* BANNER DE VERSIÓN OBSOLETA */}
      {latestDocInfo && (
          <div className="bg-indigo-600 border-l-4 border-white p-4 rounded-xl flex flex-col md:flex-row items-center justify-between gap-4 animate-fadeIn shadow-lg text-white">
              <div className="flex items-center gap-3">
                  <div className="p-2 bg-white/20 rounded-lg">
                      <HistoryIcon size={24} />
                  </div>
                  <div>
                      <p className="text-sm font-black uppercase tracking-tighter">Estás viendo una versión antigua</p>
                      <p className="text-xs opacity-90 font-medium">Existe una versión más reciente para este microproceso: <span className="font-black bg-white/20 px-1 rounded">{formatVersionForDisplay(latestDocInfo.version)}</span></p>
                  </div>
              </div>
              <button 
                onClick={() => navigate(`/doc/${latestDocInfo.id}`)} 
                className="flex items-center gap-2 px-6 py-2 bg-white text-indigo-600 rounded-lg text-xs font-black uppercase tracking-widest hover:bg-slate-50 transition-all shadow-md active:scale-95"
              >
                  Ir a versión actual
                  <ChevronRight size={14} />
              </button>
          </div>
      )}

      {/* INCONSISTENCY ALERT */}
      {isInconsistent && (
          <div className="bg-amber-50 border-l-4 border-amber-400 p-4 rounded-lg flex flex-col md:flex-row items-center justify-between gap-4 animate-fadeIn shadow-sm">
              <div className="flex items-center gap-3">
                  <AlertTriangle className="text-amber-500 shrink-0" size={24} />
                  <div>
                      <p className="text-sm font-black text-amber-900 uppercase tracking-tighter">Inconsistencia Detectada en Metadatos</p>
                      <p className="text-xs text-amber-800 font-medium">
                          La versión "{formatVersionForDisplay(doc.version)}" no coincide con el estado o la alerta de gestión actual.
                      </p>
                  </div>
              </div>
              <button 
                onClick={handleSyncState} 
                disabled={syncing}
                className="flex items-center gap-2 px-4 py-2 bg-amber-600 text-white rounded-lg text-xs font-black uppercase tracking-widest hover:bg-amber-700 transition-all shadow-md active:scale-95 disabled:opacity-50"
              >
                  {syncing ? <RefreshCw size={14} className="animate-spin" /> : <RefreshCw size={14} />}
                  Sincronizar Estado
              </button>
          </div>
      )}

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
        <div className="flex flex-col md:flex-row md:items-start justify-between gap-4 mb-6">
            <div>
                <div className="flex items-center gap-2 mb-2">
                    {doc.project && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-slate-800 text-white tracking-wider">{doc.project}</span>}
                    {doc.docType && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-indigo-100 text-indigo-700 border border-indigo-200 tracking-wider">{doc.docType}</span>}
                    {doc.hasPendingRequest && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-blue-500 text-white animate-pulse tracking-wider">Solicitud Pendiente</span>}
                </div>
                <h1 className="text-2xl font-black text-slate-900 leading-tight">{doc.title}</h1>
                <p className="text-slate-500 text-sm font-medium mt-1">{doc.description}</p>
            </div>
            <div className={`px-3 py-2 rounded-lg text-xs font-bold tracking-wide flex items-center self-start border shadow-sm ${config.color}`}>
                <Activity size={14} className="mr-2" />{config.label}
            </div>
        </div>

        {/* GRILLA DE METADATOS ACTUALIZADA CON REFERENTES */}
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-6 text-[11px] border-t border-slate-100 pt-5">
            <div>
                <p className="text-slate-400 uppercase font-bold tracking-widest mb-1.5 flex items-center gap-1">
                    <UserIcon size={12} /> Analistas
                </p>
                {assigneeNames.length > 0 ? assigneeNames.map((name, i) => <p key={i} className="font-bold text-slate-700">{name}</p>) : <p className="font-bold text-slate-700">{doc.authorName || 'Sin Asignar'}</p>}
            </div>

            <div>
                <p className="text-slate-400 uppercase font-bold tracking-widest mb-1.5 flex items-center gap-1">
                    <UserCheck size={12} /> Referentes Técnicos
                </p>
                {referentNames.length > 0 ? (
                    referentNames.map((name, i) => <p key={i} className="font-bold text-indigo-700">{name}</p>)
                ) : (
                    <p className="font-medium text-slate-400 italic">No asignados</p>
                )}
            </div>

            <div>
                <p className="text-slate-400 uppercase font-bold tracking-widest mb-1.5 flex items-center gap-1">
                    <Layers size={12} /> Versión Actual
                </p>
                <p className="font-mono text-slate-800 font-black text-xs">{formatVersionForDisplay(doc.version)}</p>
            </div>

            <div>
                <p className="text-slate-400 uppercase font-bold tracking-widest mb-1.5 flex items-center gap-1">
                    <Activity size={12} /> Progreso
                </p>
                <div className="flex items-center gap-2">
                    <div className="flex-1 bg-slate-100 rounded-full h-2 min-w-[80px] overflow-hidden border border-slate-200">
                        <div className="bg-indigo-600 h-full rounded-full shadow-[0_0_8px_rgba(79,70,229,0.3)] transition-all duration-500" style={{ width: `${config.progress}%` }}></div>
                    </div>
                    <span className="font-black text-slate-800">{config.progress}%</span>
                </div>
            </div>

            <div>
                <p className="text-slate-400 uppercase font-bold tracking-widest mb-1.5 flex items-center gap-1">
                    <Clock size={12} /> Actualizado
                </p>
                <p className="font-bold text-slate-700">{doc.updatedAt && doc.updatedAt !== new Date(0).toISOString() ? new Date(doc.updatedAt).toLocaleDateString('es-CL') : 'Sin actividad'}</p>
            </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 items-start">
        <div className="lg:col-span-2 space-y-6">
            {(isAnalystAssigned || isCoordinatorOrAdmin) && isDocActive && (
                 <div className="flex justify-start">
                    <button type="button" onClick={handleNewRequestPrefilled} disabled={actionLoading} className="flex items-center text-white px-6 py-2.5 bg-emerald-600 hover:bg-emerald-700 rounded-xl shadow-md transition-all active:scale-95 text-[11px] font-black uppercase tracking-widest disabled:opacity-50">
                        <FilePlus size={16} className="mr-2" /> NUEVA SOLICITUD / CARGA
                    </button>
                </div>
            )}

            {!canEdit && <div className="bg-amber-50 border-l-4 border-amber-400 p-4 flex gap-3 text-xs text-amber-800 font-medium"><Lock size={18} className="text-amber-500" /> Vista de solo lectura. No tiene permisos de gestión en este documento.</div>}

            {canEdit && (
                <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
                     <h3 className="font-bold text-slate-800 mb-5 flex items-center gap-2 uppercase text-[11px] tracking-widest">
                        Acciones de Flujo
                     </h3>

                     <textarea 
                        className="w-full p-4 border border-slate-200 rounded-xl text-sm mb-5 outline-none focus:ring-4 focus:ring-indigo-500/5 focus:border-indigo-500 bg-slate-50/30 transition-all placeholder:text-slate-400" 
                        rows={4} 
                        placeholder="Escriba aquí sus observaciones o comentarios técnicos..." 
                        value={comment} 
                        onChange={(e) => setComment(e.target.value)} 
                        disabled={actionLoading}
                     />

                     <div className="flex flex-wrap gap-3">
                        <button 
                            type="button"
                            onClick={(e) => handleActionClick('COMMENT', e)} 
                            disabled={actionLoading || !comment.trim()} 
                            className="flex items-center px-5 py-2.5 bg-[#1e293b] text-white rounded-lg hover:bg-slate-800 text-sm font-bold shadow-sm transition-all active:scale-95 disabled:opacity-50"
                        >
                            <MessageSquare size={18} className="mr-2" /> {actionLoading ? 'Guardando...' : 'Guardar Observación'}
                        </button>

                        {isCoordinatorOrAdmin && (
                            <button type="button" onClick={handleNotifyAnalyst} disabled={actionLoading} className="flex items-center px-5 py-2.5 bg-white border border-slate-200 text-slate-700 hover:bg-slate-50 rounded-lg text-sm font-bold shadow-sm transition-all active:scale-95 disabled:opacity-50">
                                <Mail size={18} className="mr-2 text-indigo-500" /> Notificar Analista
                            </button>
                        )}

                        {isCoordinatorOrAdmin && referentEmails.length > 0 && [DocState.SENT_TO_REFERENT, DocState.REFERENT_REVIEW, DocState.SENT_TO_CONTROL, DocState.CONTROL_REVIEW].includes(doc.state) && (
                            <button type="button" onClick={handleNotifyReferent} disabled={actionLoading} className="flex items-center px-5 py-2.5 bg-white border border-slate-200 text-slate-700 hover:bg-slate-50 rounded-lg text-sm font-bold shadow-sm transition-all active:scale-95 disabled:opacity-50">
                                <Users size={18} className="mr-2 text-indigo-500" /> Notificar Referente
                            </button>
                        )}

                        {isAnalystAssigned && isDocActive && (
                             <button type="button" onClick={handleNotifyCoordinator} disabled={actionLoading} className="flex items-center px-5 py-2.5 bg-white border border-slate-200 text-slate-700 hover:bg-slate-50 rounded-lg text-sm font-bold shadow-sm transition-all active:scale-95 disabled:opacity-50">
                                <Mail size={18} className="mr-2 text-indigo-500" /> Notificar Coordinador
                            </button>
                        )}

                        {canReview && isDocActive && (
                            <button 
                                type="button"
                                onClick={(e) => handleActionClick('APPROVE', e)} 
                                disabled={actionLoading} 
                                className="flex items-center px-6 py-2.5 bg-[#22c55e] text-white rounded-lg hover:bg-green-600 text-sm font-bold shadow-md shadow-green-100 transition-all active:scale-95 disabled:opacity-50"
                            >
                                <CheckCircle size={18} className="mr-2" /> Aprobar
                            </button>
                        )}

                        {canReview && isDocActive && (
                            <button 
                                type="button"
                                onClick={(e) => handleActionClick('REJECT', e)} 
                                disabled={actionLoading} 
                                className="flex items-center px-5 py-2.5 bg-red-50 text-red-600 hover:bg-red-100 rounded-lg text-sm font-bold border border-red-100 transition-all active:scale-95 disabled:opacity-50"
                            >
                                <XCircle size={18} className="mr-2" /> Rechazar
                            </button>
                        )}
                     </div>
                </div>
            )}
        </div>

        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 flex flex-col min-h-[550px]">
            <h3 className="font-bold text-slate-800 mb-6 border-b border-slate-100 pb-4 text-sm">Historial Completo</h3>

            <div className="flex-1 overflow-y-auto pr-3 custom-scrollbar">
                {history.length === 0 ? (
                  <div className="flex flex-col items-center justify-center py-16 text-slate-300">
                      <Clock size={40} className="mb-3 opacity-20" />
                      <p className="text-xs font-bold uppercase tracking-widest">Sin registros</p>
                  </div>
                ) : (
                  <div className="space-y-10 pl-5 border-l-[1.5px] border-slate-100 relative ml-2">
                      {history.map((h) => (
                          <div key={h.id} className="relative group animate-fadeIn">
                              <div className="absolute -left-[23px] top-2 h-3 w-3 rounded-full bg-slate-300 border-2 border-white shadow-sm ring-4 ring-white group-hover:bg-indigo-500 transition-colors"></div>
                              <div className="text-[11px] font-bold text-slate-400 mb-1 flex items-center gap-1.5 uppercase tracking-tighter">
                                  {formatDate(h.timestamp)}
                              </div>
                              <div className="text-[13px] text-slate-700 mb-2">
                                  <span className="font-black text-slate-900">{h.action}</span>
                                  <span className="mx-1.5 font-medium text-slate-400 text-xs">por</span>
                                  <span className="font-black text-slate-800">{h.userName}</span>
                              </div>
                              <div className="mb-2.5">
                                  <span className="inline-block px-2 py-0.5 rounded bg-slate-100 text-slate-500 text-[10px] font-black border border-slate-200 uppercase tracking-tighter">
                                      Versión: {formatVersionForDisplay(h.version || '-')}
                                  </span>
                              </div>
                              {h.comment && (
                                  <div className="bg-slate-50/80 border border-slate-100 rounded-lg p-3.5 text-xs italic text-slate-600 leading-relaxed shadow-sm relative overflow-hidden">
                                      <div className="absolute top-0 left-0 w-1 h-full bg-slate-200/50"></div>
                                      "{h.comment}"
                                  </div>
                              )}
                          </div>
                      ))}
                  </div>
                )}
            </div>

            {doc.id.startsWith('virtual-') && (
              <div className="mt-6 p-4 bg-amber-50 rounded-xl border border-amber-100 flex items-start gap-3 shadow-sm">
                  <Info className="text-amber-600 flex-shrink-0" size={18} />
                  <p className="text-xs text-amber-800 font-bold leading-tight">Este microproceso aún no posee documentos cargados (Estado Pendiente).</p>
              </div>
            )}
        </div>
      </div>

      {showResponseModal && pendingAction && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-fadeIn">
              <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden border border-slate-100">
                  <div className={`p-5 border-b border-slate-100 flex justify-between items-center ${pendingAction === 'APPROVE' ? 'bg-green-50' : 'bg-red-50'}`}>
                      <h3 className={`text-lg font-black flex items-center gap-2 ${pendingAction === 'APPROVE' ? 'text-green-800' : 'text-red-800'}`}>{pendingAction === 'APPROVE' ? <CheckCircle size={24} /> : <XCircle size={24} />}{pendingAction === 'APPROVE' ? 'Aprobar Solicitud' : 'Rechazar Solicitud'}</h3>
                      <button type="button" onClick={() => setShowResponseModal(false)} className="text-slate-400 hover:text-slate-600 transition-colors"><XCircle size={20} /></button>
                  </div>
                  <div className="p-6 space-y-4">
                        <div className="p-4 bg-blue-50 border border-blue-100 rounded-xl flex flex-col gap-2">
                            <div className="flex items-start gap-3">
                                <Info size={20} className="text-blue-600 mt-0.5 flex-shrink-0" />
                                <div>
                                    <p className="text-xs font-black text-blue-800 uppercase mb-1">Carga de Documento Requerida</p>
                                    <p className="text-xs text-blue-900 leading-relaxed font-bold">{getCoordinatorRuleHint(doc.state, pendingAction)}</p>
                                </div>
                            </div>
                        </div>

                        <div className={`border-2 border-dashed rounded-2xl p-8 transition-all flex flex-col items-center justify-center text-center group relative ${isFileValid ? 'border-green-400 bg-green-50/50' : fileError.length > 0 ? 'border-red-400 bg-red-50/50' : 'border-slate-200 hover:border-indigo-400 hover:bg-slate-50'}`}>
                            <input type="file" ref={fileInputRef} onChange={handleResponseFileSelect} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" disabled={actionLoading} />
                            {responseFile ? (
                                isFileValid ? (
                                    <div className="text-green-700 animate-fadeIn">
                                        <CheckCircle size={40} className="mx-auto mb-3" />
                                        <p className="font-black text-sm">{responseFile.name}</p>
                                        <p className="text-[10px] mt-1 font-black uppercase opacity-60">Versión Detectada: {formatVersionForDisplay(detectedVersion)}</p>
                                    </div>
                                ) : (
                                    <div className="text-red-600 animate-fadeIn">
                                        <FileX size={40} className="mx-auto mb-3" />
                                        <p className="font-black text-sm">{responseFile.name}</p>
                                        <div className="mt-3 text-xs text-left bg-white p-2 rounded-lg border border-red-100">
                                            <ul className="list-disc pl-4 space-y-1 font-bold">{fileError.map((err, idx) => <li key={idx}>{err}</li>)}</ul>
                                        </div>
                                    </div>
                                )
                            ) : (
                                <div className="text-slate-400 group-hover:text-indigo-600 transition-colors">
                                    <Upload size={40} className="mx-auto mb-3 opacity-50" />
                                    <p className="font-black text-sm uppercase tracking-wider">Haga clic para cargar respuesta</p>
                                    <p className="text-[10px] mt-1 opacity-60 font-bold">Nomenclatura institucional obligatoria.</p>
                                </div>
                            )}
                        </div>

                        <div className="flex justify-end gap-3 pt-4">
                            <button type="button" onClick={() => setShowResponseModal(false)} className="px-4 py-2 text-slate-500 hover:text-slate-800 text-sm font-black uppercase tracking-tighter transition-colors">Cancelar</button>
                            <button type="button" onClick={(e) => handleSubmitResponse(e)} disabled={!isFileValid || actionLoading} className={`px-6 py-2 rounded-lg text-white text-sm font-black shadow-md transition-all flex items-center gap-2 ${pendingAction === 'APPROVE' ? 'bg-green-600 hover:bg-green-700' : 'bg-red-600 hover:bg-red-700'} disabled:opacity-50 disabled:grayscale`}>
                                <Save size={16} />{actionLoading ? 'Procesando...' : `Confirmar ${pendingAction === 'APPROVE' ? 'Aprobación' : 'Rechazo'}`}
                            </button>
                        </div>
                  </div>
              </div>
          </div>
      )}

      {/* REVERT / DELETE MODAL */}
      {showDeleteModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-fadeIn">
              <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden border border-red-100">
                  <div className="p-5 border-b border-red-50 bg-red-50 flex justify-between items-center">
                      <h3 className="text-lg font-black flex items-center gap-2 text-red-800">
                          <AlertTriangle size={24} /> 
                          Revertir Última Acción
                      </h3>
                      <button type="button" onClick={() => setShowDeleteModal(false)} className="text-red-400 hover:text-red-600 transition-colors">
                          <XCircle size={20} />
                      </button>
                  </div>
                  <div className="p-6">
                      <div className="bg-amber-50 border border-amber-100 p-4 rounded-xl mb-6">
                          <p className="text-sm text-amber-800 font-bold leading-relaxed">
                              ⚠️ Esta acción eliminará el último hito registrado en el historial y restaurará el documento a su <b>estado, versión y progreso inmediatamente anterior</b>.
                          </p>
                          <p className="text-xs text-amber-700 mt-2">
                              Si este es el único hito del documento, el registro completo será eliminado.
                          </p>
                      </div>

                      <div className="flex flex-col gap-3">
                          <button 
                            type="button"
                            onClick={handleRevertAction}
                            disabled={actionLoading}
                            className="w-full flex items-center justify-center gap-2 py-3 bg-red-600 hover:bg-red-700 text-white rounded-xl font-black uppercase tracking-widest text-xs shadow-lg shadow-red-100 transition-all active:scale-95 disabled:opacity-50"
                          >
                              {actionLoading ? 'Procesando...' : <><Trash2 size={16} /> Confirmar Reversión</>}
                          </button>
                          <button 
                            type="button"
                            onClick={() => setShowDeleteModal(false)}
                            className="w-full py-3 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded-xl font-bold uppercase tracking-widest text-xs transition-all"
                          >
                              Cancelar
                          </button>
                      </div>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

export default DocumentDetail;

export enum UserRole {
  ADMIN = 'ADMIN',
  COORDINATOR = 'COORDINATOR',
  ANALYST = 'ANALYST',
  GUEST = 'GUEST',
}

export interface User {
  id: string;
  email: string;
  name: string;
  nickname?: string;
  role: UserRole;
  avatar: string;
  organization: string;
  password?: string;
  active?: boolean;
  canAccessReports?: boolean;
  canAccessReferents?: boolean;
  canAccessGantt?: boolean;
}

export interface Referent {
  id: string;
  name: string;
  email: string;
  specialty: string;
  organization: string;
}

export enum DocState {
  NOT_STARTED = 'NOT_STARTED',
  INITIATED = 'INITIATED',
  IN_PROCESS = 'IN_PROCESS',
  INTERNAL_REVIEW = 'INTERNAL_REVIEW',
  SENT_TO_REFERENT = 'SENT_TO_REFERENT',
  REFERENT_REVIEW = 'REFERENT_REVIEW',
  SENT_TO_CONTROL = 'SENT_TO_CONTROL',
  CONTROL_REVIEW = 'CONTROL_REVIEW',
  APPROVED = 'APPROVED',
  REJECTED = 'REJECTED'
}

export type DocType = 'AS IS' | 'FCE' | 'PM' | 'TO BE';

export interface DocFile {
  id: string;
  name: string;
  size: number;
  type: string;
  url: string;
  uploadedAt: string;
}

export interface DocHistory {
  id: string;
  documentId: string;
  userId: string;
  userName: string;
  action: string;
  previousState: DocState;
  newState: DocState;
  version?: string;
  comment: string;
  timestamp: string;
}

export interface Notification {
  id: string;
  userId: string;
  documentId: string;
  type: 'ASSIGNMENT' | 'APPROVAL' | 'REJECTION' | 'COMMENT' | 'UPLOAD';
  title: string;
  message: string;
  isRead: boolean;
  timestamp: string;
  actorName: string;
}

export interface Document {
  id: string;
  title: string;
  description: string;
  project?: string;
  macroprocess?: string;
  process?: string;
  microprocess?: string;
  docType?: DocType;
  authorId: string;
  authorName: string;
  assignedTo?: string;
  assignees: string[];
  assignedByName?: string;
  state: DocState;
  version: string;
  progress: number;
  hasPendingRequest?: boolean;
  files: DocFile[];
  createdAt: string;
  updatedAt: string;
  expectedEndDate?: string;
}

export interface ProcessNode {
  name: string;
  docId: string;
  assignees: string[];
  referentIds?: string[];
  requiredTypes: DocType[];
  active?: boolean;
}

export interface FullHierarchy {
  [project: string]: {
    [macro: string]: {
      [process: string]: ProcessNode[];
    };
  };
}

export interface UserHierarchy {
  [project: string]: {
    [macro: string]: {
      [process: string]: string[];
    };
  };
}

export interface ParsedFilenameResult {
  valido: boolean;
  errores: string[];
  proyecto?: 'HPC' | 'HSR';
  microproceso?: string;
  tipo?: string;
  nomenclatura?: string;
  estado?: string;
  porcentaje?: number;
}

import React, { useEffect, useState, useRef } from 'react';
import { useParams, useNavigate, useLocation, Link } from 'react-router-dom';
import { DocumentService, HistoryService, UserService, HierarchyService, ReferentService, normalizeHeader, determineStateFromVersion, formatVersionForDisplay } from '../services/firebaseBackend';
import { Document, User, DocHistory, UserRole, DocState, FullHierarchy, Referent } from '../types';
import { STATE_CONFIG } from '../constants';
import { parseDocumentFilename, validateCoordinatorRules, getCoordinatorRuleHint } from '../utils/filenameParser';
import { ArrowLeft, FileText, CheckCircle, XCircle, Activity, Paperclip, Mail, MessageSquare, Send, FileCheck, FileX, Info, ListFilter, Trash2, Lock, Save, PlusCircle, Calendar, Upload, ExternalLink, Clock, User as UserIcon, Users, ArrowRight, History as HistoryIcon, Layers, AlertTriangle, FilePlus, RefreshCw, ChevronRight, UserCheck, Eye } from 'lucide-react';

interface Props {
  user: User;
}

const DocumentDetail: React.FC<Props> = ({ user }) => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const location = useLocation(); 

  const [doc, setDoc] = useState<Document | null>(null);
  const [history, setHistory] = useState<DocHistory[]>([]);
  const [assigneeNames, setAssigneeNames] = useState<string[]>([]);
  const [assigneeEmails, setAssigneeEmails] = useState<string[]>([]);
  const [referentEmails, setReferentEmails] = useState<string[]>([]);
  const [referentNames, setReferentNames] = useState<string[]>([]);
  const [coordinatorEmail, setCoordinatorEmail] = useState<string>('');
  const [authorEmail, setAuthorEmail] = useState<string>('');
  const [loading, setLoading] = useState(true);
  const [comment, setComment] = useState('');
  const [actionLoading, setActionLoading] = useState(false);
  const [syncing, setSyncing] = useState(false);

  // --- GUARDIAS DE SEGURIDAD CONTRA DUPLICIDAD ---
  const isProcessing = useRef(false);
  const lastExecutionTime = useRef(0);

  const [showResponseModal, setShowResponseModal] = useState(false);
  const [pendingAction, setPendingAction] = useState<'APPROVE' | 'REJECT' | null>(null);
  const [responseFile, setResponseFile] = useState<File | null>(null);
  const [fileError, setFileError] = useState<string[]>([]);
  const [isFileValid, setIsFileValid] = useState(false);
  const [detectedVersion, setDetectedVersion] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [showDeleteModal, setShowDeleteModal] = useState(false);

  // Estado para detectar si hay una versión más nueva
  const [latestDocInfo, setLatestDocInfo] = useState<{ id: string, version: string } | null>(null);

  useEffect(() => {
    if (location.state?.docData) {
        const passedDoc = location.state.docData;
        setDoc(passedDoc);
        if (!passedDoc.id.startsWith('virtual-')) {
             loadAuxiliaryData(passedDoc.id, passedDoc);
        } else {
             setLoading(false);
             if (passedDoc.assignees && passedDoc.assignees.length > 0) {
                 UserService.getAll().then(users => {
                     const names = passedDoc.assignees.map((aid: string) => users.find(u => u.id === aid)?.name).filter((n: string | undefined) => n) as string[];
                     setAssigneeNames(names);
                 });
             }
        }
    } else if (id && !id.startsWith('virtual-')) {
        loadData(id);
    } else {
        setLoading(false);
    }
  }, [id, location.state]);

  const loadAuxiliaryData = async (docId: string, currentDoc: Document) => {
      try {
          const relatedIds = await DocumentService.getRelatedDocIds(
              currentDoc.project!, 
              currentDoc.microprocess || currentDoc.title.split(' - ')[0], 
              currentDoc.docType!
          );

          const [h, allUsers, hierarchy, allReferents, allDocs] = await Promise.all([
              HistoryService.getHistory(relatedIds),
              UserService.getAll(),
              HierarchyService.getFullHierarchy(),
              ReferentService.getAll(),
              DocumentService.getAll()
          ]);

          setHistory(h);

          // Detectar si este documento es el más reciente de su grupo
          const relatedDocs = allDocs.filter(d => relatedIds.includes(d.id));
          if (relatedDocs.length > 1) {
              const latest = [...relatedDocs].sort((a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime())[0];
              if (latest && latest.id !== currentDoc.id) {
                  setLatestDocInfo({ id: latest.id, version: latest.version });
              } else {
                  setLatestDocInfo(null);
              }
          } else {
              setLatestDocInfo(null);
          }

          const coordinator = allUsers.find(u => ['COORDINATOR', 'COORDINADOR', 'ADMIN'].includes((u.role || '').toString().toUpperCase()));
          if (coordinator) setCoordinatorEmail(coordinator.email);
          const author = allUsers.find(u => u.id === currentDoc.authorId);
          if (author) setAuthorEmail(author.email);

          const matrix = resolveMatrixData(currentDoc, hierarchy, allReferents);
          setReferentEmails(matrix.referentEmails);
          setReferentNames(matrix.referentNames);

          if (matrix.assignees.length > 0) {
              const names = matrix.assignees.map(aid => allUsers.find(u => u.id === aid)?.name).filter(n => n) as string[];
              setAssigneeNames(names);
              const emails = matrix.assignees.map(aid => allUsers.find(u => u.id === aid)?.email).filter(e => e) as string[];
              setAssigneeEmails(emails);
          }
          setLoading(false);
      } catch (e) {
          console.error("Error loading aux data", e);
          setLoading(false);
      }
  };

  const resolveMatrixData = (d: Document, hierarchy: FullHierarchy, allReferents: Referent[]) => {
      let resolvedAssigneeIds = d.assignees || [];
      let resolvedReferentEmails: string[] = [];
      let resolvedReferentNames: string[] = [];

      if (d.project && d.microprocess) {
           const targetMicro = normalizeHeader(d.microprocess);
           const targetProject = normalizeHeader(d.project);
           let node: any = null;
           for (const projKey of Object.keys(hierarchy)) {
               if (normalizeHeader(projKey) === targetProject) {
                   for (const macroKey of Object.keys(hierarchy[projKey])) {
                       for (const procKey of Object.keys(hierarchy[projKey][macroKey])) {
                           const found = hierarchy[projKey][macroKey][procKey].find(n => normalizeHeader(n.name) === targetMicro);
                           if (found) { node = found; break; }
                       }
                       if (node) break;
                   }
               }
               if (node) break;
           }

           // Si encontramos el nodo en la matriz, usamos sus referentes vinculados
           if (node?.assignees && (resolvedAssigneeIds.length === 0 || d.authorName.includes('Sistema'))) resolvedAssigneeIds = node.assignees;
           if (node?.referentIds && node.referentIds.length > 0) {
               const matches = allReferents.filter(r => node.referentIds.includes(r.id));
               resolvedReferentEmails = matches.map(r => r.email);
               resolvedReferentNames = matches.map(r => r.name);
           }
      }
      return { assignees: resolvedAssigneeIds, referentEmails: resolvedReferentEmails, referentNames: resolvedReferentNames };
  };

  const loadData = async (docId: string) => {
    setLoading(true);
    try {
        const d = await DocumentService.getById(docId);
        if (d) {
            setDoc(d);
            await loadAuxiliaryData(docId, d);
        } else {
            setDoc(null);
            setLoading(false);
        }
    } catch (error) {
        console.error("Error loading document data:", error);
        setDoc(null);
        setLoading(false);
    }
  };

  const handleSyncState = async () => {
      if (!doc || syncing) return;
      setSyncing(true);
      try {
          await DocumentService.syncMetadata(doc.id, user);
          await loadData(doc.id);
      } catch (e: any) {
          alert("Error al sincronizar: " + e.message);
      } finally {
          setSyncing(false);
      }
  };

  const getDocLink = () => `${window.location.origin}/#/doc/${doc?.id}`;

  const handleNotifyAnalyst = () => {
      if (!doc || assigneeEmails.length === 0) {
          alert("No hay correos de analistas definidos para este proceso.");
          return;
      }
      const displayVersion = formatVersionForDisplay(doc.version);
      const subject = encodeURIComponent(`Respuesta Solicitud: ${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${displayVersion}`);
      const body = encodeURIComponent(`Estimada/o,\nAdjunto el Informe: ${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${displayVersion}\n\nEstado Actual: ${STATE_CONFIG[doc.state].label}\n\nPuede revisar el detalle y los comentarios en: ${getDocLink()}\n\nSaludos\n${user.name}`);
      window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${encodeURIComponent(assigneeEmails.join(','))}&su=${subject}&body=${body}`, '_blank');
  };

  const handleNotifyReferent = () => {
      if (!doc || referentEmails.length === 0) {
          alert("No hay correos de referentes vinculados a este proceso en la matriz.");
          return;
      }
      const displayVersion = formatVersionForDisplay(doc.version);
      const subject = encodeURIComponent(`Revisión Técnica: ${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${displayVersion}`);
      const greeting = referentNames.length > 0 ? `Estimada/o ${referentNames.join(', ')}` : 'Estimados Referentes';
      const body = encodeURIComponent(`${greeting},\n\nSe solicita su validación para el documento: ${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${displayVersion}\n\nQuedamos atentos a sus observaciones.\n\nSaludos\n${user.name}`);
      window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${encodeURIComponent(referentEmails.join(','))}&su=${subject}&body=${body}`, '_blank');
  };

  const handleNotifyCoordinator = () => {
    if (!doc || !coordinatorEmail) { alert(`Aviso: No se ha detectado correo del coordinador.`); return; }
    const displayVersion = formatVersionForDisplay(doc.version);
    const subject = encodeURIComponent(`Solicitud de Revisión: ${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${displayVersion}`);
    const body = encodeURIComponent(`Estimado,\nPara su revisión, he cargado el documento "${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${displayVersion}",\n\nLink: ${getDocLink()}\n\nSaludos\n${user.name}`);
    window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${coordinatorEmail}&su=${subject}&body=${body}`, '_blank');
  };

  const handleActionClick = async (action: 'ADVANCE' | 'APPROVE' | 'REJECT' | 'COMMENT', e?: React.MouseEvent) => {
      if (e) { e.preventDefault(); e.stopPropagation(); }

      const now = Date.now();
      if (now - lastExecutionTime.current < 3000) return;

      if (!doc || isProcessing.current) return;
      isProcessing.current = true;
      lastExecutionTime.current = now;

      if (action === 'COMMENT') {
          const currentComment = comment.trim();
          if (!currentComment) { 
              alert('Escribe una observación.'); 
              isProcessing.current = false; 
              return; 
          }

          setActionLoading(true);
          setComment(''); 

          try {
              await DocumentService.transitionState(doc.id, user, 'COMMENT', currentComment);
              await loadData(doc.id);
          } catch (err: any) {
              alert('Error al guardar: ' + err.message);
              setComment(currentComment);
          } finally {
              isProcessing.current = false;
              setActionLoading(false);
          }
          return;
      }

      if (action === 'ADVANCE') { 
          setActionLoading(true);
          try {
              await DocumentService.transitionState(doc.id, user, 'ADVANCE', 'Gestión de flujo.');
              await loadData(doc.id);
          } finally {
              isProcessing.current = false;
              setActionLoading(false);
          }
          return; 
      }

      if (action === 'APPROVE' || action === 'REJECT') {
          if (action === 'REJECT' && !comment) { 
              alert('Agrega una observación para el rechazo.'); 
              isProcessing.current = false; 
              return; 
          }
          setPendingAction(action); setResponseFile(null); setFileError([]); setIsFileValid(false); setDetectedVersion(''); setShowResponseModal(true);
          isProcessing.current = false; 
      }
  };

  const handleResponseFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0] && doc && pendingAction) {
          const f = e.target.files[0]; setResponseFile(f);
          const result = parseDocumentFilename(f.name, doc.project, doc.microprocess, doc.docType);
          if (!result.valido) { setFileError(result.errores); setIsFileValid(false); return; }
          const rules = validateCoordinatorRules(f.name, doc.version, doc.state, pendingAction);
          if (!rules.valid) { setFileError([rules.error || 'Error de validación.']); setIsFileValid(false); return; }
          setIsFileValid(true); setFileError([]); setDetectedVersion(result.nomenclatura || '');
      }
  };

  const handleSubmitResponse = async (e: React.MouseEvent) => {
      e.preventDefault(); e.stopPropagation();

      const now = Date.now();
      if (now - lastExecutionTime.current < 3000) return;
      if (!doc || !pendingAction || !responseFile || !isFileValid || isProcessing.current) return;

      isProcessing.current = true;
      lastExecutionTime.current = now;
      setActionLoading(true);
      setShowResponseModal(false); 

      try {
        await DocumentService.transitionState(
            doc.id, 
            user, 
            pendingAction, 
            comment || `Gestión realizada.`, 
            responseFile, 
            detectedVersion
        );
        setComment('');
        await loadData(doc.id);
      } catch(err: any) {
          alert('Error: ' + err.message);
      } finally {
        isProcessing.current = false;
        setActionLoading(false);
      }
  };

  const handleRevertAction = async () => {
      if (!doc || isProcessing.current) return;
      setShowDeleteModal(false);

      isProcessing.current = true;
      setLoading(true);

      try {
          const wasDeleted = await DocumentService.revertLastTransition(doc.id);
          if (wasDeleted) {
              navigate('/', { replace: true });
          } else {
              await loadData(doc.id);
          }
      } catch (e: any) {
          alert("Error al revertir: " + e.message);
          setLoading(false);
      } finally {
          isProcessing.current = false;
      }
  };

  const handleNewRequestPrefilled = () => {
      if (!doc) return;
      navigate('/new', { 
          state: { 
              prefill: { 
                  project: doc.project, 
                  macro: doc.macroprocess, 
                  process: doc.process, 
                  micro: doc.microprocess, 
                  docType: doc.docType 
              } 
          } 
      });
  };

  const formatDate = (isoString: string) => {
    const date = new Date(isoString);
    if (isNaN(date.getTime())) return 'Fecha no disponible';
    return date.toLocaleString('es-CL', { 
        day: '2-digit', month: '2-digit', year: 'numeric', 
        hour: '2-digit', minute: '2-digit', second: '2-digit',
        hour12: true 
    });
  };

  if (loading && !doc) return <div className="p-8 text-center text-slate-500 flex flex-col items-center"><RefreshCw size={24} className="animate-spin mb-2" />Cargando documento...</div>;
  if (!doc) return <div className="p-12 text-center text-slate-500">No se encontró el documento.</div>;

  const config = STATE_CONFIG[doc.state];
  const isGuest = user.role === UserRole.GUEST;
  const isAssignee = doc.assignees && doc.assignees.includes(user.id);
  const isAuthor = doc.authorId === user.id;
  const isAnalystAssigned = user.role === UserRole.ANALYST && (isAssignee || isAuthor);
  const isCoordinatorOrAdmin = user.role === UserRole.COORDINATOR || user.role === UserRole.ADMIN;
  const canEdit = !isGuest && (isAnalystAssigned || isCoordinatorOrAdmin);
  const isDocActive = doc.state !== DocState.APPROVED;

  // NUEVA LÓGICA DE DETECCIÓN DE INCONSISTENCIA (INCLUYE PENDING STATUS)
  const expectedInfo = determineStateFromVersion(doc.version);
  const expectedState = expectedInfo.state;
  const expectedPending = [
      DocState.INTERNAL_REVIEW, 
      DocState.SENT_TO_REFERENT, 
      DocState.REFERENT_REVIEW, 
      DocState.SENT_TO_CONTROL, 
      DocState.CONTROL_REVIEW
  ].includes(expectedState);

  const isInconsistent = !doc.id.startsWith('virtual-') && (doc.state !== expectedState || doc.hasPendingRequest !== expectedPending);

  const canReview = isCoordinatorOrAdmin && [DocState.INTERNAL_REVIEW, DocState.REFERENT_REVIEW, DocState.CONTROL_REVIEW, DocState.SENT_TO_REFERENT, DocState.SENT_TO_CONTROL].includes(doc.state);

  return (
    <div className="max-w-6xl mx-auto space-y-6 pb-12">
      <div className="flex justify-between items-center">
        <button onClick={() => navigate(-1)} className="flex items-center text-slate-500 hover:text-slate-800 text-sm font-medium transition-colors">
            <ArrowLeft size={16} className="mr-1" /> Volver
        </button>
        <div className="flex items-center gap-2">
            {user.role === UserRole.ADMIN && !doc.id.startsWith('virtual-') && (
                <button type="button" onClick={() => setShowDeleteModal(true)} disabled={actionLoading} className="flex items-center text-red-500 hover:text-red-700 text-[11px] font-bold uppercase tracking-wider px-3 py-1.5 bg-red-50 hover:bg-red-100 rounded-lg border border-red-100 transition-colors shadow-sm disabled:opacity-50">
                    <Trash2 size={14} className="mr-1.5" /> Eliminar
                </button>
            )}
        </div>
      </div>

      {/* BANNER DE VERSIÓN OBSOLETA */}
      {latestDocInfo && (
          <div className="bg-indigo-600 border-l-4 border-white p-4 rounded-xl flex flex-col md:flex-row items-center justify-between gap-4 animate-fadeIn shadow-lg text-white">
              <div className="flex items-center gap-3">
                  <div className="p-2 bg-white/20 rounded-lg">
                      <HistoryIcon size={24} />
                  </div>
                  <div>
                      <p className="text-sm font-black uppercase tracking-tighter">Estás viendo una versión antigua</p>
                      <p className="text-xs opacity-90 font-medium">Existe una versión más reciente para este microproceso: <span className="font-black bg-white/20 px-1 rounded">{formatVersionForDisplay(latestDocInfo.version)}</span></p>
                  </div>
              </div>
              <button 
                onClick={() => navigate(`/doc/${latestDocInfo.id}`)} 
                className="flex items-center gap-2 px-6 py-2 bg-white text-indigo-600 rounded-lg text-xs font-black uppercase tracking-widest hover:bg-slate-50 transition-all shadow-md active:scale-95"
              >
                  Ir a versión actual
                  <ChevronRight size={14} />
              </button>
          </div>
      )}

      {/* INCONSISTENCY ALERT */}
      {isInconsistent && isCoordinatorOrAdmin && (
          <div className="bg-amber-50 border-l-4 border-amber-400 p-4 rounded-lg flex flex-col md:flex-row items-center justify-between gap-4 animate-fadeIn shadow-sm">
              <div className="flex items-center gap-3">
                  <AlertTriangle className="text-amber-500 shrink-0" size={24} />
                  <div>
                      <p className="text-sm font-black text-amber-900 uppercase tracking-tighter">Inconsistencia Detectada en Metadatos</p>
                      <p className="text-xs text-amber-800 font-medium">
                          La versión "{formatVersionForDisplay(doc.version)}" no coincide con el estado o la alerta de gestión actual.
                      </p>
                  </div>
              </div>
              <button 
                onClick={handleSyncState} 
                disabled={syncing}
                className="flex items-center gap-2 px-4 py-2 bg-amber-600 text-white rounded-lg text-xs font-black uppercase tracking-widest hover:bg-amber-700 transition-all shadow-md active:scale-95 disabled:opacity-50"
              >
                  {syncing ? <RefreshCw size={14} className="animate-spin" /> : <RefreshCw size={14} />}
                  Sincronizar Estado
              </button>
          </div>
      )}

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
        <div className="flex flex-col md:flex-row md:items-start justify-between gap-4 mb-6">
            <div>
                <div className="flex items-center gap-2 mb-2">
                    {doc.project && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-slate-800 text-white tracking-wider">{doc.project}</span>}
                    {doc.docType && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-indigo-100 text-indigo-700 border border-indigo-200 tracking-wider">{doc.docType}</span>}
                    {doc.hasPendingRequest && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-blue-500 text-white animate-pulse tracking-wider">Solicitud Pendiente</span>}
                </div>
                <h1 className="text-2xl font-black text-slate-900 leading-tight">{doc.title}</h1>
                <p className="text-slate-500 text-sm font-medium mt-1">{doc.description}</p>
            </div>
            <div className={`px-3 py-2 rounded-lg text-xs font-bold tracking-wide flex items-center self-start border shadow-sm ${config.color}`}>
                <Activity size={14} className="mr-2" />{config.label}
            </div>
        </div>

        {/* GRILLA DE METADATOS ACTUALIZADA CON REFERENTES */}
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-6 text-[11px] border-t border-slate-100 pt-5">
            <div>
                <p className="text-slate-400 uppercase font-bold tracking-widest mb-1.5 flex items-center gap-1">
                    <UserIcon size={12} /> Analistas
                </p>
                {assigneeNames.length > 0 ? assigneeNames.map((name, i) => <p key={i} className="font-bold text-slate-700">{name}</p>) : <p className="font-bold text-slate-700">{doc.authorName || 'Sin Asignar'}</p>}
            </div>

            <div>
                <p className="text-slate-400 uppercase font-bold tracking-widest mb-1.5 flex items-center gap-1">
                    <UserCheck size={12} /> Referentes
                </p>
                {referentNames.length > 0 ? (
                    referentNames.map((name, i) => <p key={i} className="font-bold text-indigo-700">{name}</p>)
                ) : (
                    <p className="font-medium text-slate-400 italic">No asignados</p>
                )}
            </div>

            <div>
                <p className="text-slate-400 uppercase font-bold tracking-widest mb-1.5 flex items-center gap-1">
                    <Layers size={12} /> Versión Actual
                </p>
                <p className="font-mono text-slate-800 font-black text-xs">{formatVersionForDisplay(doc.version)}</p>
            </div>

            <div>
                <p className="text-slate-400 uppercase font-bold tracking-widest mb-1.5 flex items-center gap-1">
                    <Activity size={12} /> Progreso
                </p>
                <div className="flex items-center gap-2">
                    <div className="flex-1 bg-slate-100 rounded-full h-2 min-w-[80px] overflow-hidden border border-slate-200">
                        <div className="bg-indigo-600 h-full rounded-full shadow-[0_0_8px_rgba(79,70,229,0.3)] transition-all duration-500" style={{ width: `${config.progress}%` }}></div>
                    </div>
                    <span className="font-black text-slate-800">{config.progress}%</span>
                </div>
            </div>

            <div>
                <p className="text-slate-400 uppercase font-bold tracking-widest mb-1.5 flex items-center gap-1">
                    <Clock size={12} /> Actualizado
                </p>
                <p className="font-bold text-slate-700">{doc.updatedAt && doc.updatedAt !== new Date(0).toISOString() ? new Date(doc.updatedAt).toLocaleDateString('es-CL') : 'Sin actividad'}</p>
            </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 items-start">
        <div className="lg:col-span-2 space-y-6">
            {(isAnalystAssigned || isCoordinatorOrAdmin) && isDocActive && !isGuest && (
                 <div className="flex justify-start">
                    <button type="button" onClick={handleNewRequestPrefilled} disabled={actionLoading} className="flex items-center text-white px-6 py-2.5 bg-emerald-600 hover:bg-emerald-700 rounded-xl shadow-md transition-all active:scale-95 text-[11px] font-black uppercase tracking-widest disabled:opacity-50">
                        <FilePlus size={16} className="mr-2" /> NUEVA SOLICITUD / CARGA
                    </button>
                </div>
            )}

            {isGuest && (
              <div className="bg-slate-100 border-l-4 border-slate-400 p-4 flex gap-3 text-xs text-slate-600 font-bold items-center shadow-sm">
                <Eye size={20} className="text-slate-500" />
                Modo Consulta: Usted tiene permisos de solo lectura. No puede realizar gestiones sobre este documento.
              </div>
            )}

            {!canEdit && !isGuest && <div className="bg-amber-50 border-l-4 border-amber-400 p-4 flex gap-3 text-xs text-amber-800 font-medium"><Lock size={18} className="text-amber-500" /> Vista de solo lectura. No tiene permisos de gestión en este documento.</div>}

            {canEdit && (
                <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
                     <h3 className="font-bold text-slate-800 mb-5 flex items-center gap-2 uppercase text-[11px] tracking-widest">
                        Acciones de Flujo
                     </h3>

                     <textarea 
                        className="w-full p-4 border border-slate-200 rounded-xl text-sm mb-5 outline-none focus:ring-4 focus:ring-indigo-500/5 focus:border-indigo-500 bg-slate-50/30 transition-all placeholder:text-slate-400" 
                        rows={4} 
                        placeholder="Escriba aquí sus observaciones o comentarios técnicos..." 
                        value={comment} 
                        onChange={(e) => setComment(e.target.value)} 
                        disabled={actionLoading}
                     />

                     <div className="flex flex-wrap gap-3">
                        <button 
                            type="button"
                            onClick={(e) => handleActionClick('COMMENT', e)} 
                            disabled={actionLoading || !comment.trim()} 
                            className="flex items-center px-5 py-2.5 bg-[#1e293b] text-white rounded-lg hover:bg-slate-800 text-sm font-bold shadow-sm transition-all active:scale-95 disabled:opacity-50"
                        >
                            <MessageSquare size={18} className="mr-2" /> {actionLoading ? 'Guardando...' : 'Guardar Observación'}
                        </button>

                        {isCoordinatorOrAdmin && (
                            <button type="button" onClick={handleNotifyAnalyst} disabled={actionLoading} className="flex items-center px-5 py-2.5 bg-white border border-slate-200 text-slate-700 hover:bg-slate-50 rounded-lg text-sm font-bold shadow-sm transition-all active:scale-95 disabled:opacity-50">
                                <Mail size={18} className="mr-2 text-indigo-500" /> Notificar Analista
                            </button>
                        )}

                        {isCoordinatorOrAdmin && referentEmails.length > 0 && [DocState.SENT_TO_REFERENT, DocState.REFERENT_REVIEW, DocState.SENT_TO_CONTROL, DocState.CONTROL_REVIEW].includes(doc.state) && (
                            <button type="button" onClick={handleNotifyReferent} disabled={actionLoading} className="flex items-center px-5 py-2.5 bg-white border border-slate-200 text-slate-700 hover:bg-slate-50 rounded-lg text-sm font-bold shadow-sm transition-all active:scale-95 disabled:opacity-50">
                                <Users size={18} className="mr-2 text-indigo-500" /> Notificar Referente
                            </button>
                        )}

                        {isAnalystAssigned && isDocActive && (
                             <button type="button" onClick={handleNotifyCoordinator} disabled={actionLoading} className="flex items-center px-5 py-2.5 bg-white border border-slate-200 text-slate-700 hover:bg-slate-50 rounded-lg text-sm font-bold shadow-sm transition-all active:scale-95 disabled:opacity-50">
                                <Mail size={18} className="mr-2 text-indigo-500" /> Notificar Coordinador
                            </button>
                        )}

                        {canReview && isDocActive && (
                            <button 
                                type="button"
                                onClick={(e) => handleActionClick('APPROVE', e)} 
                                disabled={actionLoading} 
                                className="flex items-center px-6 py-2.5 bg-[#22c55e] text-white rounded-lg hover:bg-green-600 text-sm font-bold shadow-md shadow-green-100 transition-all active:scale-95 disabled:opacity-50"
                            >
                                <CheckCircle size={18} className="mr-2" /> Aprobar
                            </button>
                        )}

                        {canReview && isDocActive && (
                            <button 
                                type="button"
                                onClick={(e) => handleActionClick('REJECT', e)} 
                                disabled={actionLoading} 
                                className="flex items-center px-5 py-2.5 bg-red-50 text-red-600 hover:bg-red-100 rounded-lg text-sm font-bold border border-red-100 transition-all active:scale-95 disabled:opacity-50"
                            >
                                <XCircle size={18} className="mr-2" /> Rechazar
                            </button>
                        )}
                     </div>
                </div>
            )}
        </div>

        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 flex flex-col min-h-[550px]">
            <h3 className="font-bold text-slate-800 mb-6 border-b border-slate-100 pb-4 text-sm">Historial Completo</h3>

            <div className="flex-1 overflow-y-auto pr-3 custom-scrollbar">
                {history.length === 0 ? (
                  <div className="flex flex-col items-center justify-center py-16 text-slate-300">
                      <Clock size={40} className="mb-3 opacity-20" />
                      <p className="text-xs font-bold uppercase tracking-widest">Sin registros</p>
                  </div>
                ) : (
                  <div className="space-y-10 pl-5 border-l-[1.5px] border-slate-100 relative ml-2">
                      {history.map((h) => (
                          <div key={h.id} className="relative group animate-fadeIn">
                              <div className="absolute -left-[23px] top-2 h-3 w-3 rounded-full bg-slate-300 border-2 border-white shadow-sm ring-4 ring-white group-hover:bg-indigo-500 transition-colors"></div>
                              <div className="text-[11px] font-bold text-slate-400 mb-1 flex items-center gap-1.5 uppercase tracking-tighter">
                                  {formatDate(h.timestamp)}
                              </div>
                              <div className="text-[13px] text-slate-700 mb-2">
                                  <span className="font-black text-slate-900">{h.action}</span>
                                  <span className="mx-1.5 font-medium text-slate-400 text-xs">por</span>
                                  <span className="font-black text-slate-800">{h.userName}</span>
                              </div>
                              <div className="mb-2.5">
                                  <span className="inline-block px-2 py-0.5 rounded bg-slate-100 text-slate-500 text-[10px] font-black border border-slate-200 uppercase tracking-tighter">
                                      Versión: {formatVersionForDisplay(h.version || '-')}
                                  </span>
                              </div>
                              {h.comment && (
                                  <div className="bg-slate-50/80 border border-slate-100 rounded-lg p-3.5 text-xs italic text-slate-600 leading-relaxed shadow-sm relative overflow-hidden">
                                      <div className="absolute top-0 left-0 w-1 h-full bg-slate-200/50"></div>
                                      "{h.comment}"
                                  </div>
                              )}
                          </div>
                      ))}
                  </div>
                )}
            </div>

            {doc.id.startsWith('virtual-') && (
              <div className="mt-6 p-4 bg-amber-50 rounded-xl border border-amber-100 flex items-start gap-3 shadow-sm">
                  <Info className="text-amber-600 flex-shrink-0" size={18} />
                  <p className="text-xs text-amber-800 font-bold leading-tight">Este microproceso aún no posee documentos cargados (Estado Pendiente).</p>
              </div>
            )}
        </div>
      </div>

      {showResponseModal && pendingAction && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-fadeIn">
              <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden border border-slate-100">
                  <div className={`p-5 border-b border-slate-100 flex justify-between items-center ${pendingAction === 'APPROVE' ? 'bg-green-50' : 'bg-red-50'}`}>
                      <h3 className={`text-lg font-black flex items-center gap-2 ${pendingAction === 'APPROVE' ? 'text-green-800' : 'text-red-800'}`}>{pendingAction === 'APPROVE' ? <CheckCircle size={24} /> : <XCircle size={24} />}{pendingAction === 'APPROVE' ? 'Aprobar Solicitud' : 'Rechazar Solicitud'}</h3>
                      <button type="button" onClick={() => setShowResponseModal(false)} className="text-slate-400 hover:text-slate-600 transition-colors"><XCircle size={20} /></button>
                  </div>
                  <div className="p-6 space-y-4">
                        <div className="p-4 bg-blue-50 border border-blue-100 rounded-xl flex flex-col gap-2">
                            <div className="flex items-start gap-3">
                                <Info size={20} className="text-blue-600 mt-0.5 flex-shrink-0" />
                                <div>
                                    <p className="text-xs font-black text-blue-800 uppercase mb-1">Carga de Documento Requerida</p>
                                    <p className="text-xs text-blue-900 leading-relaxed font-bold">{getCoordinatorRuleHint(doc.state, pendingAction)}</p>
                                </div>
                            </div>
                        </div>

                        <div className={`border-2 border-dashed rounded-2xl p-8 transition-all flex flex-col items-center justify-center text-center group relative ${isFileValid ? 'border-green-400 bg-green-50/50' : fileError.length > 0 ? 'border-red-400 bg-red-50/50' : 'border-slate-200 hover:border-indigo-400 hover:bg-slate-50'}`}>
                            <input type="file" ref={fileInputRef} onChange={handleResponseFileSelect} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" disabled={actionLoading} />
                            {responseFile ? (
                                isFileValid ? (
                                    <div className="text-green-700 animate-fadeIn">
                                        <CheckCircle size={40} className="mx-auto mb-3" />
                                        <p className="font-black text-sm">{responseFile.name}</p>
                                        <p className="text-[10px] mt-1 font-black uppercase opacity-60">Versión Detectada: {formatVersionForDisplay(detectedVersion)}</p>
                                    </div>
                                ) : (
                                    <div className="text-red-600 animate-fadeIn">
                                        <FileX size={40} className="mx-auto mb-3" />
                                        <p className="font-black text-sm">{responseFile.name}</p>
                                        <div className="mt-3 text-xs text-left bg-white p-2 rounded-lg border border-red-100">
                                            <ul className="list-disc pl-4 space-y-1 font-bold">{fileError.map((err, idx) => <li key={idx}>{err}</li>)}</ul>
                                        </div>
                                    </div>
                                )
                            ) : (
                                <div className="text-slate-400 group-hover:text-indigo-600 transition-colors">
                                    <Upload size={40} className="mx-auto mb-3 opacity-50" />
                                    <p className="font-black text-sm uppercase tracking-wider">Haga clic para cargar respuesta</p>
                                    <p className="text-[10px] mt-1 opacity-60 font-bold">Nomenclatura institucional obligatoria.</p>
                                </div>
                            )}
                        </div>

                        <div className="flex justify-end gap-3 pt-4">
                            <button type="button" onClick={() => setShowResponseModal(false)} className="px-4 py-2 text-slate-500 hover:text-slate-800 text-sm font-black uppercase tracking-tighter transition-colors">Cancelar</button>
                            <button type="button" onClick={(e) => handleSubmitResponse(e)} disabled={!isFileValid || actionLoading} className={`px-6 py-2 rounded-lg text-white text-sm font-black shadow-md transition-all flex items-center gap-2 ${pendingAction === 'APPROVE' ? 'bg-green-600 hover:bg-green-700' : 'bg-red-600 hover:bg-red-700'} disabled:opacity-50 disabled:grayscale`}>
                                <Save size={16} />{actionLoading ? 'Procesando...' : `Confirmar ${pendingAction === 'APPROVE' ? 'Aprobación' : 'Rechazo'}`}
                            </button>
                        </div>
                  </div>
              </div>
          </div>
      )}

      {/* REVERT / DELETE MODAL */}
      {showDeleteModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-fadeIn">
              <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden border border-red-100">
                  <div className="p-5 border-b border-red-50 bg-red-50 flex justify-between items-center">
                      <h3 className="text-lg font-black flex items-center gap-2 text-red-800">
                          <AlertTriangle size={24} /> 
                          Revertir Última Acción
                      </h3>
                      <button type="button" onClick={() => setShowDeleteModal(false)} className="text-red-400 hover:text-red-600 transition-colors">
                          <XCircle size={20} />
                      </button>
                  </div>
                  <div className="p-6">
                      <div className="bg-amber-50 border border-amber-100 p-4 rounded-xl mb-6">
                          <p className="text-sm text-amber-800 font-bold leading-relaxed">
                              ⚠️ Esta acción eliminará el último hito registrado en el historial y restaurará el documento a su <b>estado, versión y progreso inmediatamente anterior</b>.
                          </p>
                          <p className="text-xs text-amber-700 mt-2">
                              Si este es el único hito del documento, el registro completo será eliminado.
                          </p>
                      </div>

                      <div className="flex flex-col gap-3">
                          <button 
                            type="button"
                            onClick={handleRevertAction}
                            disabled={actionLoading}
                            className="w-full flex items-center justify-center gap-2 py-3 bg-red-600 hover:bg-red-700 text-white rounded-xl font-black uppercase tracking-widest text-xs shadow-lg shadow-red-100 transition-all active:scale-95 disabled:opacity-50"
                          >
                              {actionLoading ? 'Procesando...' : <><Trash2 size={16} /> Confirmar Reversión</>}
                          </button>
                          <button 
                            type="button"
                            onClick={() => setShowDeleteModal(false)}
                            className="w-full py-3 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded-xl font-bold uppercase tracking-widest text-xs transition-all"
                          >
                              Cancelar
                          </button>
                      </div>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

export default DocumentDetail;

import React, { useState, useEffect } from 'react';
import { useLocation, Link, useNavigate } from 'react-router-dom';
import { Menu, X, FileText, BarChart2, PlusCircle, LogOut, User as UserIcon, Users, ClipboardList, Inbox, Database, Settings, ListTodo, Network, PieChart, UserCheck, BookOpen, CalendarRange } from 'lucide-react';
import { User, UserRole, DocState, Document } from '../types';
import { NotificationService } from '../services/firebaseBackend';

interface LayoutProps {
  children: React.ReactNode;
  user: User;
  onLogout: () => void;
}

const Layout: React.FC<LayoutProps> = ({ children, user, onLogout }) => {
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [inboxCount, setInboxCount] = useState(0);
  const location = useLocation();

  const isActive = (path: string) => location.pathname === path ? 'bg-slate-800 text-white shadow-inner' : 'text-slate-300 hover:bg-slate-800 hover:text-white';

  useEffect(() => {
    if (!user?.id) return;

    // Establishing reliable real-time connection for notification badge
    const unsubscribeBadge = NotificationService.subscribeToUnreadCount(user.id, (count) => {
        setInboxCount(count);
    });

    return () => {
        if (unsubscribeBadge) unsubscribeBadge();
    };
  }, [user?.id]); 

  const NavItem = ({ to, icon: Icon, label, badge }: { to: string, icon: any, label: string, badge?: number }) => (
    <Link
      to={to}
      onClick={() => setIsSidebarOpen(false)}
      className={`flex items-center space-x-3 px-4 py-3 rounded-lg transition-all duration-200 group ${isActive(to)}`}
    >
      <div className="relative">
        <Icon 
            size={20} 
            className={isActive(to).includes('bg-slate-800') ? 'text-indigo-400' : 'text-slate-400 group-hover:text-white'} 
        />
        {badge !== undefined && badge > 0 && (
            <span className="absolute -top-2.5 -right-2.5 flex h-5 w-5 items-center justify-center rounded-full bg-red-600 text-[10px] font-black text-white shadow-md ring-2 ring-slate-900 animate-pulse px-1">
                {badge > 99 ? '99+' : badge}
            </span>
        )}
      </div>
      <span className="font-medium flex-1">{label}</span>
    </Link>
  );

  const isGuest = user.role === UserRole.GUEST;
  const isAdminOrCoord = user.role === UserRole.ADMIN || user.role === UserRole.COORDINATOR;

  const canAccessReports = isAdminOrCoord || ((user.role === UserRole.ANALYST || isGuest) && user.canAccessReports);
  const canAccessReferents = isAdminOrCoord || (user.role === UserRole.ANALYST && user.canAccessReferents);
  const canAccessGantt = isAdminOrCoord || ((user.role === UserRole.ANALYST || isGuest) && user.canAccessGantt);

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      {isSidebarOpen && (
        <div className="fixed inset-0 bg-black/60 z-20 md:hidden backdrop-blur-sm transition-opacity" onClick={() => setIsSidebarOpen(false)} />
      )}
      <aside className={`fixed inset-y-0 left-0 z-30 w-64 bg-slate-900 text-white transform transition-transform duration-300 ease-in-out md:translate-x-0 md:static md:flex-shrink-0 ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="h-full flex flex-col">
          <div className="p-6 border-b border-slate-800 flex justify-between items-center flex-shrink-0 bg-slate-950/30">
            <div>
                <h1 className="text-xl font-bold tracking-tight text-white">SGD</h1>
                <p className="text-[10px] text-indigo-400 font-bold uppercase tracking-widest">{isGuest ? 'Visor Institucional' : 'Gestión Documental'}</p>
            </div>
            <button onClick={() => setIsSidebarOpen(false)} className="md:hidden text-slate-400 hover:text-white">
                <X size={24} />
            </button>
          </div>
          <nav className="flex-1 px-4 py-6 space-y-1.5 overflow-y-auto">
            <div className="pb-2 text-[10px] font-bold text-slate-500 uppercase tracking-widest px-4">Exploración</div>
            <NavItem to="/" icon={BarChart2} label="Dashboard" />

            {!isGuest && (
              <>
                <NavItem to="/inbox" icon={Inbox} label="Bandeja de Entrada" badge={inboxCount} />
                <NavItem to="/worklist" icon={ListTodo} label="Lista de Trabajo" />
                <NavItem to="/new" icon={PlusCircle} label="Nueva Solicitud" />
              </>
            )}

            {(canAccessReports || canAccessReferents || canAccessGantt || isAdminOrCoord) && (
              <>
                <div className="pt-6 pb-2 text-[10px] font-bold text-slate-500 uppercase tracking-widest px-4">Visualización y Análisis</div>
                {canAccessReports && <NavItem to="/admin/reports" icon={PieChart} label="Reportes" />}
                {canAccessGantt && <NavItem to="/admin/gantt" icon={CalendarRange} label="Diagrama Gantt" />}
                {isAdminOrCoord && (
                    <>
                        <NavItem to="/admin/structure" icon={Network} label="Estructura" />
                        <NavItem to="/admin/assignments" icon={ClipboardList} label="Asignaciones" />
                    </>
                )}
                {canAccessReferents && <NavItem to="/admin/referents" icon={UserCheck} label="Referentes" />}
                {user.role === UserRole.ADMIN && (
                    <>
                        <NavItem to="/admin/database" icon={Database} label="Base de Datos" />
                        <NavItem to="/admin/users" icon={Users} label="Usuarios" />
                    </>
                )}
              </>
            )}
            <div className="pt-6 pb-2 text-[10px] font-bold text-slate-500 uppercase tracking-widest px-4">Mi Cuenta</div>
            {!isGuest && <NavItem to="/manual" icon={BookOpen} label="Manual de Usuario" />}
            <NavItem to="/profile" icon={Settings} label="Mi Perfil" />
          </nav>
          <div className="p-4 border-t border-slate-800 flex-shrink-0 bg-slate-950/20">
            <button onClick={onLogout} className="w-full flex items-center justify-center space-x-2 bg-slate-800 hover:bg-red-900/40 hover:text-red-200 p-2.5 rounded-lg transition-all text-sm font-semibold border border-transparent hover:border-red-800/50">
                <LogOut size={16} />
                <span>Cerrar Sesión</span>
            </button>
          </div>
        </div>
      </aside>
      <div className="flex-1 flex flex-col h-screen overflow-hidden">
        <header className="bg-white border-b border-gray-200 p-4 flex items-center justify-between md:hidden flex-shrink-0 shadow-sm">
            <button onClick={() => setIsSidebarOpen(true)} className="text-slate-600 hover:bg-slate-50 p-1 rounded-md"><Menu size={24} /></button>
            <div className="flex flex-col items-center">
              <span className="font-bold text-slate-900 text-sm">SGD Visor</span>
              <span className="text-[10px] text-indigo-600 font-bold uppercase tracking-tight">Acceso Lectura</span>
            </div>
            <div className="w-6" />
        </header>
        <main className="flex-1 overflow-y-auto p-4 md:p-8 bg-slate-50/50">{children}</main>
      </div>
    </div>
  );
};

export default Layout;

import React, { useState, useEffect } from 'react';
import { UserService } from '../services/firebaseBackend';
import { User, UserRole } from '../types';
import { Trash2, UserPlus, Shield, Briefcase, User as UserIcon, X, Lock, Pencil, Power, AlertCircle, CheckCircle, PieChart, UserCheck, Loader2, CalendarRange } from 'lucide-react';

const AdminUsers: React.FC = () => {
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [editingUserId, setEditingUserId] = useState<string | null>(null);
  const [updatingId, setUpdatingId] = useState<string | null>(null);

  // Form State
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [nickname, setNickname] = useState('');
  const [role, setRole] = useState<UserRole>(UserRole.ANALYST);
  const [organization, setOrganization] = useState('');
  const [password, setPassword] = useState('');
  const [canAccessReports, setCanAccessReports] = useState(false);
  const [canAccessReferents, setCanAccessReferents] = useState(false);
  const [canAccessGantt, setCanAccessGantt] = useState(false);

  useEffect(() => {
    loadUsers();
  }, []);

  const loadUsers = async () => {
    setLoading(true);
    const data = await UserService.getAll();
    setUsers(data);
    setLoading(false);
  };

  const handleTogglePermission = async (user: User, field: 'canAccessReports' | 'canAccessReferents' | 'canAccessGantt') => {
      setUpdatingId(`${user.id}-${field}`);
      const newValue = !user[field];
      try {
          await UserService.update(user.id, { [field]: newValue });
          // Actualización optimista local
          setUsers(prev => prev.map(u => u.id === user.id ? { ...u, [field]: newValue } : u));
      } catch (error) {
          console.error(error);
          alert('Error al actualizar permisos');
      } finally {
          setUpdatingId(null);
      }
  };

  const handleDelete = async (id: string) => {
    if (!window.confirm('¿Estás seguro de que quieres eliminar permanentemente este usuario? Esta acción es irreversible.')) return;
    try {
        await UserService.delete(id);
        await loadUsers();
    } catch (error) {
        console.error(error);
    }
  };

  const handleToggleStatus = async (user: User) => {
      const action = user.active !== false ? 'inactivar' : 'activar';
      if (!window.confirm(`¿Está seguro que desea ${action} al usuario ${user.name}?`)) return;

      try {
          await UserService.toggleActiveStatus(user.id, user.active !== false);
          await loadUsers();
      } catch (error) {
          console.error(error);
          alert('Error al cambiar estado del usuario');
      }
  };

  const handleEdit = (user: User) => {
      setEditingUserId(user.id);
      setName(user.name);
      setEmail(user.email);
      setNickname(user.nickname || '');
      setRole(user.role);
      setOrganization(user.organization);
      setPassword(''); 
      setCanAccessReports(user.canAccessReports || false);
      setCanAccessReferents(user.canAccessReferents || false);
      setCanAccessGantt(user.canAccessGantt || false);
      setShowForm(true);
  };

  const handleCreateNew = () => {
      setEditingUserId(null);
      resetForm();
      setShowForm(true);
  };

  const handleCancel = () => {
      setShowForm(false);
      resetForm();
      setEditingUserId(null);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!name || !email || !organization) return;

    let finalEmail = email;
    if (!finalEmail.includes('@')) {
        finalEmail += '@ugp-ssmso.cl';
    }

    try {
        if (editingUserId) {
            const updatePayload: Partial<User> = {
                name,
                email: finalEmail,
                nickname: nickname || undefined,
                role,
                organization,
                canAccessReports: (role === UserRole.ANALYST || role === UserRole.GUEST) ? canAccessReports : true,
                canAccessReferents: role === UserRole.ANALYST ? canAccessReferents : (role === UserRole.GUEST ? false : true),
                canAccessGantt: (role === UserRole.ANALYST || role === UserRole.GUEST) ? canAccessGantt : true
            };
            if (password) {
                updatePayload.password = password;
            }
            await UserService.update(editingUserId, updatePayload);
        } else {
            await UserService.create({
                id: `user-${Date.now()}`,
                name,
                email: finalEmail,
                nickname: nickname || undefined,
                role,
                organization,
                password: password || undefined,
                active: true,
                canAccessReports: (role === UserRole.ANALYST || role === UserRole.GUEST) ? canAccessReports : false,
                canAccessReferents: role === UserRole.ANALYST ? canAccessReferents : false,
                canAccessGantt: (role === UserRole.ANALYST || role === UserRole.GUEST) ? canAccessGantt : false
            } as User);
        }

        setShowForm(false);
        resetForm();
        setEditingUserId(null);
        await loadUsers();
    } catch (err: any) {
        alert(err.message);
    }
  };

  const resetForm = () => {
      setName('');
      setEmail('');
      setNickname('');
      setOrganization('');
      setRole(UserRole.ANALYST);
      setPassword('');
      setCanAccessReports(false);
      setCanAccessReferents(false);
      setCanAccessGantt(false);
  };

  return (
    <div className="space-y-6">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
            <div>
                <h1 className="text-2xl font-bold text-slate-900">Gestión de Usuarios</h1>
                <p className="text-slate-500">Administra perfiles, permisos y estados de acceso.</p>
            </div>
            <button 
                onClick={showForm ? handleCancel : handleCreateNew}
                className={`inline-flex items-center px-4 py-2 text-white rounded-lg transition-colors shadow-sm ${showForm ? 'bg-slate-500 hover:bg-slate-600' : 'bg-indigo-600 hover:bg-indigo-700'}`}
            >
                {showForm ? <X size={18} className="mr-2" /> : <UserPlus size={18} className="mr-2" />}
                {showForm ? 'Cancelar' : 'Nuevo Usuario'}
            </button>
        </div>

        {showForm && (
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 animate-fadeIn">
                <h2 className="font-semibold text-slate-800 mb-4">{editingUserId ? 'Editar Usuario' : 'Registrar Nuevo Usuario'}</h2>
                <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">Nombre Completo</label>
                        <input type="text" value={name} onChange={(e) => setName(e.target.value)} className="w-full px-3 py-2 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" required />
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">Email</label>
                        <input type="text" value={email} onChange={(e) => setEmail(e.target.value)} className="w-full px-3 py-2 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" required placeholder="usuario@ugp-ssmso.cl" />
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">Usuario Corto / Nickname</label>
                        <input type="text" value={nickname} onChange={(e) => setNickname(e.target.value)} className="w-full px-3 py-2 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" placeholder="Ej: jsmith" />
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">Contraseña</label>
                        <input type="text" value={password} onChange={(e) => setPassword(e.target.value)} className="w-full px-3 py-2 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" placeholder={editingUserId ? "••••••••" : "Opcional"} />
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">Organización / Área</label>
                        <input type="text" value={organization} onChange={(e) => setOrganization(e.target.value)} className="w-full px-3 py-2 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" required />
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">Rol</label>
                        <select value={role} onChange={(e) => setRole(e.target.value as UserRole)} className="w-full px-3 py-2 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500">
                            <option value={UserRole.ANALYST}>Analista</option>
                            <option value={UserRole.GUEST}>Visita (Solo Lectura)</option>
                            <option value={UserRole.COORDINATOR}>Coordinador</option>
                            <option value={UserRole.ADMIN}>Administrador</option>
                        </select>
                    </div>

                    {/* SECCIÓN DE PERMISOS PARA ANALISTAS Y VISITAS */}
                    {(role === UserRole.ANALYST || role === UserRole.GUEST) && (
                        <div className="md:col-span-2 bg-indigo-50 p-4 rounded-lg border border-indigo-100 mt-2">
                            <h3 className="text-xs font-bold text-indigo-900 uppercase mb-3 flex items-center gap-2">
                                <Shield size={14} /> Permisos de Acceso ({role === UserRole.GUEST ? 'Visita' : 'Analista'})
                            </h3>
                            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                                <label className="flex items-center gap-3 p-2 bg-white rounded border border-indigo-200 cursor-pointer hover:bg-indigo-100/50 transition-colors">
                                    <input 
                                        type="checkbox" 
                                        checked={canAccessReports}
                                        onChange={(e) => setCanAccessReports(e.target.checked)}
                                        className="w-4 h-4 text-indigo-600 rounded focus:ring-indigo-500"
                                    />
                                    <div className="flex items-center gap-2">
                                        <PieChart size={16} className="text-indigo-500" />
                                        <span className="text-sm font-medium text-slate-700">Reportes</span>
                                    </div>
                                </label>

                                {role === UserRole.ANALYST && (
                                    <label className="flex items-center gap-3 p-2 bg-white rounded border border-indigo-200 cursor-pointer hover:bg-indigo-100/50 transition-colors">
                                        <input 
                                            type="checkbox" 
                                            checked={canAccessReferents}
                                            onChange={(e) => setCanAccessReferents(e.target.checked)}
                                            className="w-4 h-4 text-indigo-600 rounded focus:ring-indigo-500"
                                        />
                                        <div className="flex items-center gap-2">
                                            <UserCheck size={16} className="text-indigo-500" />
                                            <span className="text-sm font-medium text-slate-700">Referentes</span>
                                        </div>
                                    </label>
                                )}

                                <label className="flex items-center gap-3 p-2 bg-white rounded border border-indigo-200 cursor-pointer hover:bg-indigo-100/50 transition-colors">
                                    <input 
                                        type="checkbox" 
                                        checked={canAccessGantt}
                                        onChange={(e) => setCanAccessGantt(e.target.checked)}
                                        className="w-4 h-4 text-indigo-600 rounded focus:ring-indigo-500"
                                    />
                                    <div className="flex items-center gap-2">
                                        <CalendarRange size={16} className="text-indigo-500" />
                                        <span className="text-sm font-medium text-slate-700">Diagrama Gantt</span>
                                    </div>
                                </label>
                            </div>
                        </div>
                    )}

                    <div className="md:col-span-2 flex justify-end mt-2">
                        <button type="submit" className="bg-indigo-600 text-white px-6 py-2 rounded-lg hover:bg-indigo-700 transition-colors">
                            {editingUserId ? 'Guardar Cambios' : 'Crear Usuario'}
                        </button>
                    </div>
                </form>
            </div>
        )}

        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="overflow-x-auto">
                <table className="w-full text-sm text-left">
                    <thead className="text-xs text-slate-500 uppercase bg-slate-50">
                        <tr>
                            <th className="px-6 py-3">Usuario</th>
                            <th className="px-6 py-3">Permisos</th>
                            <th className="px-6 py-3 text-center">Estado</th>
                            <th className="px-6 py-3">Rol</th>
                            <th className="px-6 py-3">Organización</th>
                            <th className="px-6 py-3 text-right">Acciones</th>
                        </tr>
                    </thead>
                    <tbody>
                        {users.map(u => (
                            <tr key={u.id} className={`border-b border-slate-50 hover:bg-slate-50 transition-colors ${u.active === false ? 'opacity-60 bg-slate-50/50' : ''}`}>
                                <td className="px-6 py-4 flex items-center gap-3">
                                    <img src={u.avatar} alt={u.name} className="w-8 h-8 rounded-full bg-slate-200" />
                                    <div>
                                        <p className="font-medium text-slate-900">{u.name}</p>
                                        <p className="text-xs text-slate-500">{u.email}</p>
                                    </div>
                                </td>
                                <td className="px-6 py-4">
                                    <div className="flex items-center gap-2">
                                        {/* BOTÓN REPORTE */}
                                        <button 
                                            onClick={() => handleTogglePermission(u, 'canAccessReports')}
                                            disabled={updatingId === `${u.id}-canAccessReports`}
                                            className={`p-1.5 rounded-lg transition-all flex items-center justify-center
                                                ${u.canAccessReports !== false 
                                                    ? 'bg-green-50 text-green-600 hover:bg-green-100' 
                                                    : 'bg-slate-50 text-slate-300 hover:bg-slate-100 hover:text-slate-400'}`}
                                            title={u.canAccessReports !== false ? "Deshabilitar Reportes" : "Habilitar Reportes"}
                                        >
                                            {updatingId === `${u.id}-canAccessReports` ? <Loader2 size={14} className="animate-spin" /> : <PieChart size={14} />}
                                        </button>

                                        {/* BOTÓN REFERENTES */}
                                        {u.role !== UserRole.GUEST && (
                                            <button 
                                                onClick={() => handleTogglePermission(u, 'canAccessReferents')}
                                                disabled={updatingId === `${u.id}-canAccessReferents`}
                                                className={`p-1.5 rounded-lg transition-all flex items-center justify-center
                                                    ${u.canAccessReferents !== false 
                                                        ? 'bg-indigo-50 text-indigo-600 hover:bg-indigo-100' 
                                                        : 'bg-slate-50 text-slate-300 hover:bg-slate-100 hover:text-slate-400'}`}
                                                title={u.canAccessReferents !== false ? "Deshabilitar Referentes" : "Habilitar Referentes"}
                                            >
                                                {updatingId === `${u.id}-canAccessReferents` ? <Loader2 size={14} className="animate-spin" /> : <UserCheck size={14} />}
                                            </button>
                                        )}

                                        {/* BOTÓN GANTT */}
                                        <button 
                                            onClick={() => handleTogglePermission(u, 'canAccessGantt')}
                                            disabled={updatingId === `${u.id}-canAccessGantt`}
                                            className={`p-1.5 rounded-lg transition-all flex items-center justify-center
                                                ${u.canAccessGantt !== false 
                                                    ? 'bg-amber-50 text-amber-600 hover:bg-amber-100' 
                                                    : 'bg-slate-50 text-slate-300 hover:bg-slate-100 hover:text-slate-400'}`}
                                            title={u.canAccessGantt !== false ? "Deshabilitar Gantt" : "Habilitar Gantt"}
                                        >
                                            {updatingId === `${u.id}-canAccessGantt` ? <Loader2 size={14} className="animate-spin" /> : <CalendarRange size={14} />}
                                        </button>
                                    </div>
                                </td>
                                <td className="px-6 py-4 text-center">
                                    <span className={`inline-flex items-center px-2 py-0.5 rounded-full text-[10px] font-bold uppercase ${u.active !== false ? 'bg-green-100 text-green-700 border border-green-200' : 'bg-slate-200 text-slate-500 border border-slate-300'}`}>
                                        {u.active !== false ? 'Activo' : 'Inactivo'}
                                    </span>
                                </td>
                                <td className="px-6 py-4">
                                    <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium 
                                        ${u.role === UserRole.ADMIN ? 'bg-purple-100 text-purple-800' : 
                                          u.role === UserRole.COORDINATOR ? 'bg-blue-100 text-blue-800' : 
                                          u.role === UserRole.GUEST ? 'bg-slate-100 text-slate-600' :
                                          'bg-green-100 text-green-800'}`}>
                                        {u.role === UserRole.GUEST ? 'Visita' : u.role}
                                    </span>
                                </td>
                                <td className="px-6 py-4 text-slate-600">{u.organization}</td>
                                <td className="px-6 py-4 text-right">
                                    <div className="flex justify-end gap-1">
                                        <button 
                                            onClick={() => handleToggleStatus(u)}
                                            className={`p-1.5 rounded transition-colors ${u.active !== false ? 'text-slate-400 hover:text-red-600 hover:bg-red-50' : 'text-slate-400 hover:text-green-600 hover:bg-green-50'}`}
                                            title={u.active !== false ? "Inactivar usuario" : "Activar usuario"}
                                        >
                                            <Power size={18} />
                                        </button>
                                        <button 
                                            onClick={() => handleEdit(u)}
                                            className="text-slate-400 hover:text-indigo-600 p-1.5 hover:bg-indigo-50 rounded transition-colors"
                                            title="Editar usuario"
                                        >
                                            <Pencil size={18} />
                                        </button>
                                        <button 
                                            onClick={() => handleDelete(u.id)}
                                            className="text-slate-400 hover:text-red-600 p-1.5 hover:bg-red-50 rounded transition-colors"
                                            title="Eliminar permanentemente"
                                        >
                                            <Trash2 size={18} />
                                        </button>
                                    </div>
                                </td>
                            </tr>
                        ))}
                        {users.length === 0 && !loading && (
                            <tr><td colSpan={6} className="px-6 py-8 text-center text-slate-400">No hay usuarios registrados.</td></tr>
                        )}
                    </tbody>
                </table>
            </div>
        </div>
    </div>
  );
};

export default AdminUsers;

import React, { useEffect, useState, useMemo } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { DocumentService, UserService, HierarchyService, normalizeHeader, formatVersionForDisplay } from '../services/firebaseBackend';
import { Document, User, UserRole, DocState, DocType, FullHierarchy } from '../types';
import { STATE_CONFIG } from '../constants';
import { 
    Plus, Clock, CheckCircle, Filter, X, Activity, 
    BookOpen, Users, ShieldCheck, ArrowUp, ArrowDown, ArrowUpDown, Loader2,
    User as UserIcon, Database, Archive, Search,
    ChevronLeft, ChevronRight, FileSpreadsheet, ListTodo, Layers
} from 'lucide-react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';

interface DashboardProps {
  user: User;
}

interface DashboardDoc extends Document {
    isRequired: boolean;
}

type SortKey = 'project' | 'microprocess' | 'state' | 'updatedAt';
type QuickFilterType = 'ALL' | 'NOT_STARTED' | 'IN_PROCESS' | 'REFERENT' | 'CONTROL' | 'FINISHED';

const ITEMS_PER_PAGE = 10;

const getDocTypeOrder = (type: string | undefined): number => {
    switch (type) {
        case 'AS IS': return 1;
        case 'FCE': return 2;
        case 'PM': return 3;
        case 'TO BE': return 4;
        default: return 99;
    }
};

const Dashboard: React.FC<DashboardProps> = ({ user }) => {
  const navigate = useNavigate();
  const location = useLocation(); 

  const [mergedDocs, setMergedDocs] = useState<DashboardDoc[]>([]);
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [isSystemEmpty, setIsSystemEmpty] = useState(false);

  // Filtros de Estado
  const [filterProject, setFilterProject] = useState('');
  const [filterMacro, setFilterMacro] = useState('');
  const [filterProcess, setFilterProcess] = useState('');
  const [filterSearch, setFilterSearch] = useState(''); 
  const [filterDocType, setFilterDocType] = useState('');
  const [filterState, setFilterState] = useState(''); 
  const [filterAnalyst, setFilterAnalyst] = useState('');

  // Paginación
  const [currentPage, setCurrentPage] = useState(1);
  const [externalFilterIds, setExternalFilterIds] = useState<string[] | null>(null);
  const [quickFilter, setQuickFilter] = useState<QuickFilterType>('ALL');

  const [sortConfig, setSortConfig] = useState<{ key: SortKey; direction: 'asc' | 'desc' }>({
    key: 'project', 
    direction: 'asc'
  });

  useEffect(() => {
    if (location.state?.filterIds && Array.isArray(location.state.filterIds)) {
        setExternalFilterIds(location.state.filterIds);
        setQuickFilter('ALL');
    } else {
        setExternalFilterIds(null);
    }
    loadData();
  }, [location.state]);

  useEffect(() => {
    setCurrentPage(1);
  }, [filterProject, filterMacro, filterProcess, filterSearch, filterDocType, filterState, filterAnalyst, quickFilter, sortConfig]);

  const loadData = async () => {
    setLoading(true);
    try {
        const [realDocsData, users, fullHierarchy] = await Promise.all([
            DocumentService.getAll(),
            UserService.getAll(),
            HierarchyService.getFullHierarchy()
        ]);

        setAllUsers(users);
        const hierarchyKeys = Object.keys(fullHierarchy);

        if (hierarchyKeys.length === 0 && realDocsData.length === 0) {
            setIsSystemEmpty(true);
            setMergedDocs([]);
            setLoading(false);
            return;
        }
        setIsSystemEmpty(false);

        const realDocMap = new Map<string, Document>();
        const processedDocIds = new Set<string>();

        realDocsData.forEach(doc => {
            if (doc.project && (doc.microprocess || doc.title)) {
                const microName = doc.microprocess || doc.title.split(' - ')[0] || doc.title;
                const docType = doc.docType || 'AS IS';
                const key = `${normalizeHeader(doc.project)}|${normalizeHeader(microName)}|${normalizeHeader(docType)}`;

                const existing = realDocMap.get(key);
                if (!existing || new Date(doc.updatedAt).getTime() > new Date(existing.updatedAt).getTime()) {
                    realDocMap.set(key, { ...doc, microprocess: microName, docType: docType as DocType });
                }
            }
        });

        const finalDocsList: DashboardDoc[] = [];

        hierarchyKeys.forEach(proj => {
            Object.keys(fullHierarchy[proj]).forEach(macro => {
                Object.keys(fullHierarchy[proj][macro]).forEach(proc => {
                    const nodes = fullHierarchy[proj][macro][proc];
                    nodes.forEach(node => {
                        if (node.active === false) return; 

                        const requiredTypes = (node.requiredTypes && node.requiredTypes.length > 0) 
                            ? node.requiredTypes 
                            : ['AS IS', 'FCE', 'PM', 'TO BE'];

                        requiredTypes.forEach(type => {
                            const key = `${normalizeHeader(proj)}|${normalizeHeader(node.name)}|${normalizeHeader(type)}`;

                            if (realDocMap.has(key)) {
                                const realDoc = realDocMap.get(key)!;
                                finalDocsList.push({
                                    ...realDoc,
                                    macroprocess: macro,
                                    process: proc,
                                    project: proj,
                                    assignees: (node.assignees && node.assignees.length > 0) ? node.assignees : (realDoc.assignees || []),
                                    isRequired: true 
                                });
                                processedDocIds.add(realDoc.id); 
                            } else {
                                finalDocsList.push({
                                    id: `virtual-${key}`, 
                                    title: `${node.name} - ${type}`,
                                    description: 'Pendiente de inicio',
                                    project: proj,
                                    macroprocess: macro,
                                    process: proc,
                                    microprocess: node.name,
                                    docType: type as DocType,
                                    authorId: '',
                                    authorName: '',
                                    assignedTo: node.assignees?.[0] || '',
                                    assignees: node.assignees || [],
                                    state: DocState.NOT_STARTED,
                                    version: '-',
                                    progress: 0,
                                    files: [],
                                    createdAt: new Date().toISOString(),
                                    updatedAt: new Date(0).toISOString(), 
                                    hasPendingRequest: false,
                                    isRequired: true 
                                });
                            }
                        });
                    });
                });
            });
        });

        realDocMap.forEach((doc) => {
            if (!processedDocIds.has(doc.id)) {
                finalDocsList.push({
                    ...doc,
                    macroprocess: doc.macroprocess || 'Sin Clasificar',
                    process: doc.process || 'Sin Clasificar',
                    isRequired: false 
                });
            }
        });

        setMergedDocs(finalDocsList);

    } catch (error) {
        console.error("Error loading dashboard data:", error);
    } finally {
        setLoading(false);
    }
  };

  const contextDocs = useMemo(() => {
      let filtered = mergedDocs;
      if (externalFilterIds && externalFilterIds.length > 0) {
          filtered = filtered.filter(d => externalFilterIds.includes(d.id));
      } else {
          if (filterProject) filtered = filtered.filter(d => d.project === filterProject);
          if (filterMacro) filtered = filtered.filter(d => d.macroprocess === filterMacro);
          if (filterProcess) filtered = filtered.filter(d => d.process === filterProcess);
          if (filterDocType) filtered = filtered.filter(d => d.docType === filterDocType);
          if (filterState) filtered = filtered.filter(d => d.state === filterState);
          if (filterAnalyst) filtered = filtered.filter(d => d.assignees && d.assignees.includes(filterAnalyst));
          if (filterSearch) {
              const term = filterSearch.toLowerCase();
              filtered = filtered.filter(d => (d.microprocess || '').toLowerCase().includes(term) || (d.title || '').toLowerCase().includes(term));
          }
      }
      return filtered;
  }, [mergedDocs, filterProject, filterMacro, filterProcess, filterDocType, filterState, filterAnalyst, filterSearch, externalFilterIds]);

  const docStats = useMemo(() => {
      const requiredDocs = contextDocs.filter(d => d.isRequired);
      return {
        total: requiredDocs.length,
        notStarted: requiredDocs.filter(d => d.state === DocState.NOT_STARTED).length,
        inProcess: requiredDocs.filter(d => d.state === DocState.INITIATED || d.state === DocState.IN_PROCESS || d.state === DocState.INTERNAL_REVIEW).length,
        referent: requiredDocs.filter(d => d.state === DocState.SENT_TO_REFERENT || d.state === DocState.REFERENT_REVIEW).length,
        control: requiredDocs.filter(d => d.state === DocState.SENT_TO_CONTROL || d.state === DocState.CONTROL_REVIEW).length,
        finished: requiredDocs.filter(d => d.state === DocState.APPROVED).length
      };
  }, [contextDocs]);

  const chartData = useMemo(() => {
    return [
      { name: 'No Iniciado', value: docStats.notStarted, color: '#94a3b8' },
      { name: 'En Proceso', value: docStats.inProcess, color: '#3b82f6' },
      { name: 'Referente', value: docStats.referent, color: '#a855f7' },
      { name: 'Control', value: docStats.control, color: '#f97316' },
      { name: 'Terminados', value: docStats.finished, color: '#22c55e' }
    ].filter(d => d.value > 0);
  }, [docStats]);

  const tableDocs = useMemo(() => {
      let filtered = contextDocs;
      if (quickFilter !== 'ALL') {
          switch (quickFilter) {
              case 'NOT_STARTED': filtered = filtered.filter(d => d.state === DocState.NOT_STARTED); break;
              case 'IN_PROCESS': filtered = filtered.filter(d => d.state === DocState.INITIATED || d.state === DocState.IN_PROCESS || d.state === DocState.INTERNAL_REVIEW); break;
              case 'REFERENT': filtered = filtered.filter(d => d.state === DocState.SENT_TO_REFERENT || d.state === DocState.REFERENT_REVIEW); break;
              case 'CONTROL': filtered = filtered.filter(d => d.state === DocState.SENT_TO_CONTROL || d.state === DocState.CONTROL_REVIEW); break;
              case 'FINISHED': filtered = filtered.filter(d => d.state === DocState.APPROVED); break;
          }
      }
      return filtered;
  }, [contextDocs, quickFilter]);

  const sortedDocs = useMemo(() => {
      return [...tableDocs].sort((a, b) => {
          if (a.isRequired !== b.isRequired) return a.isRequired ? -1 : 1;
          const modifier = sortConfig.direction === 'asc' ? 1 : -1;
          switch (sortConfig.key) {
              case 'updatedAt': return (new Date(a.updatedAt).getTime() - new Date(b.updatedAt).getTime()) * modifier;
              case 'project': 
                  if ((a.project || '') !== (b.project || '')) return (a.project || '').localeCompare(b.project || '') * modifier;
                  if ((a.macroprocess || '') !== (b.macroprocess || '')) return (a.macroprocess || '').localeCompare(b.macroprocess || '') * modifier;
                  if ((a.process || '') !== (b.process || '')) return (a.process || '').localeCompare(b.process || '') * modifier;
                  if ((a.microprocess || '') !== (b.microprocess || '')) return (a.microprocess || '').localeCompare(b.microprocess || '') * modifier;
                  return (getDocTypeOrder(a.docType) - getDocTypeOrder(b.docType)) * modifier;
              case 'microprocess': return (a.microprocess || '').localeCompare(b.microprocess || '') * modifier;
              case 'state': 
                  return (STATE_CONFIG[a.state].progress - STATE_CONFIG[b.state].progress) * modifier;
              default: return 0;
          }
      });
  }, [tableDocs, sortConfig]);

  const totalItems = sortedDocs.length;
  const totalPages = Math.ceil(totalItems / ITEMS_PER_PAGE);
  const paginatedDocs = useMemo(() => {
      const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
      return sortedDocs.slice(startIndex, startIndex + ITEMS_PER_PAGE);
  }, [sortedDocs, currentPage]);

  const visiblePageNumbers = useMemo(() => {
      const pages = [];
      const maxVisible = 5;
      let start = Math.max(1, currentPage - Math.floor(maxVisible / 2));
      let end = Math.min(totalPages, start + maxVisible - 1);

      if (end - start + 1 < maxVisible) {
          start = Math.max(1, end - maxVisible + 1);
      }

      for (let i = start; i <= end; i++) {
          pages.push(i);
      }
      return pages;
  }, [currentPage, totalPages]);

  const handleExportExcel = () => {
      if (sortedDocs.length === 0) return;
      const getUserNames = (ids: string[]) => ids.map(id => allUsers.find(u => u.id === id)?.name || id).join('; ');
      const headers = ['PROYECTO', 'MACROPROCESO', 'PROCESO', 'MICROPROCESO', 'DOCUMENTO', 'VERSION', 'ESTADO', 'FECHA', 'ANALISTA'];
      const rows = sortedDocs.map(d => [
          d.project || '-', d.macroprocess || '-', d.process || '-', d.microprocess || '-', d.docType || '-', d.version || '-',
          STATE_CONFIG[d.state]?.label.split('(')[0] || '-',
          (d.state !== DocState.NOT_STARTED && d.updatedAt) ? new Date(d.updatedAt).toLocaleDateString() : 'Sin actividad',
          getUserNames(d.assignees || [])
      ]);
      const csvContent = [headers.join(';'), ...rows.map(r => r.map(cell => `"${cell}"`).join(';'))].join('\n');
      const blob = new Blob(["\ufeff", csvContent], { type: 'text/csv;charset=utf-8;' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a'); link.setAttribute('href', url); link.setAttribute('download', `SGD_Reporte_${new Date().toISOString().split('T')[0]}.csv`);
      link.style.visibility = 'hidden'; document.body.appendChild(link); link.click(); document.body.removeChild(link);
  };

  const handleSort = (key: SortKey) => setSortConfig({ key, direction: sortConfig.key === key && sortConfig.direction === 'asc' ? 'desc' : 'asc' });
  const handleQuickFilter = (type: QuickFilterType) => { setQuickFilter(type); setCurrentPage(1); };
  const clearFilters = () => { setFilterProject(''); setFilterMacro(''); setFilterProcess(''); setFilterSearch(''); setFilterDocType(''); setFilterState(''); setFilterAnalyst(''); setQuickFilter('ALL'); setExternalFilterIds(null); navigate(location.pathname, { replace: true, state: {} }); };

  const SortIcon = ({ column }: { column: SortKey }) => (
      sortConfig.key === column ? (sortConfig.direction === 'asc' ? <ArrowUp size={12} className="text-indigo-600"/> : <ArrowDown size={12} className="text-indigo-600"/>) : <ArrowUpDown size={12} className="opacity-30 group-hover:opacity-100"/>
  );

  const availableProjects = useMemo(() => Array.from(new Set(mergedDocs.map(d => d.project).filter(Boolean))).sort(), [mergedDocs]);
  const availableMacros = useMemo(() => Array.from(new Set((filterProject ? mergedDocs.filter(d => d.project === filterProject) : mergedDocs).map(d => d.macroprocess).filter(Boolean))).sort(), [mergedDocs, filterProject]);
  const availableProcesses = useMemo(() => Array.from(new Set((mergedDocs.filter(d => (!filterProject || d.project === filterProject) && (!filterMacro || d.macroprocess === filterMacro))).map(d => d.process).filter(Boolean))).sort(), [mergedDocs, filterProject, filterMacro]);
  const getUserName = (id: string) => allUsers.find(user => user.id === id)?.name || 'Sin Asignar';

  if (loading) return <div className="p-8 text-center text-slate-500 flex flex-col items-center"><Loader2 className="animate-spin mb-2" /> Actualizando dashboard...</div>;

  const isGuest = user.role === UserRole.GUEST;

  if (isSystemEmpty) {
      return (
          <div className="flex flex-col items-center justify-center min-h-[60vh] text-center p-6 bg-white rounded-xl shadow-sm border border-slate-200">
              <div className="w-20 h-20 bg-indigo-50 rounded-full flex items-center justify-center mb-6"><Database size={40} className="text-indigo-600" /></div>
              <h2 className="text-2xl font-bold text-slate-900 mb-2">Sistema sin Inicializar</h2>
              <p className="text-slate-500 max-w-md mb-8">La matriz de procesos está vacía. Cargue la estructura de procesos para comenzar.</p>
              {(user.role === UserRole.ADMIN || user.role === UserRole.COORDINATOR) && (
                  <Link to="/admin/assignments" className="flex items-center px-6 py-3 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 font-medium shadow-md transition-transform active:scale-95">
                      <Database size={18} className="mr-2" /> Ir a Carga de Datos
                  </Link>
              )}
          </div>
      );
  }

  return (
    <div className="space-y-8 pb-12">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">Dashboard</h1>
          <p className="text-slate-500">Vista general de avance institucional {isGuest && '(Modo Lectura)'}</p>
        </div>
        <div className="flex items-center gap-2 w-full sm:w-auto">
            <button onClick={handleExportExcel} className="flex-1 sm:flex-none px-4 py-2 bg-white border border-slate-300 text-slate-700 rounded-lg hover:bg-slate-50 flex items-center justify-center shadow-sm font-medium transition-colors">
                <FileSpreadsheet size={18} className="mr-2 text-green-600"/> <span className="hidden md:inline">Exportar Excel</span><span className="md:hidden">Excel</span>
            </button>
            {user.role === UserRole.ANALYST && <Link to="/new" className="flex-1 sm:flex-none px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 flex items-center justify-center shadow-sm font-medium"><Plus size={18} className="mr-2"/> Nueva Solicitud</Link>}
        </div>
      </div>

      {/* KPI DOCUMENTOS */}
      <div className="space-y-3">
        <div className="flex items-center gap-2 px-1 text-slate-400">
            <BookOpen size={14} />
            <span className="text-[10px] font-bold uppercase tracking-wider">Estado de Documentos (Filtrable)</span>
        </div>
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-3">
            <StatCard title="Doc. Requeridos" value={docStats.total} icon={BookOpen} color="bg-slate-50 text-slate-600" onClick={() => handleQuickFilter('ALL')} isActive={quickFilter === 'ALL'}/>
            <StatCard title="No Iniciado" value={docStats.notStarted} icon={Clock} color="bg-white text-slate-600" onClick={() => handleQuickFilter('NOT_STARTED')} isActive={quickFilter === 'NOT_STARTED'}/>
            <StatCard title="En Proceso" value={docStats.inProcess} icon={Activity} color="bg-blue-50 text-blue-600" onClick={() => handleQuickFilter('IN_PROCESS')} isActive={quickFilter === 'IN_PROCESS'}/>
            <StatCard title="Referente" value={docStats.referent} icon={Users} color="bg-purple-50 text-purple-600" onClick={() => handleQuickFilter('REFERENT')} isActive={quickFilter === 'REFERENT'}/>
            <StatCard title="Control Gestión" value={docStats.control} icon={ShieldCheck} color="bg-orange-50 text-orange-600" onClick={() => handleQuickFilter('CONTROL')} isActive={quickFilter === 'CONTROL'}/>
            <StatCard title="Terminados" value={docStats.finished} icon={CheckCircle} color="bg-green-50 text-green-600" onClick={() => handleQuickFilter('FINISHED')} isActive={quickFilter === 'FINISHED'}/>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        <div className="lg:col-span-3 bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col min-h-[500px]">
            <div className="p-4 border-b border-slate-100 bg-white">
                <div className="flex items-center justify-between mb-3">
                    <div className="flex items-center gap-2 text-indigo-600 font-semibold text-sm"><Filter size={16} /> Filtros de Visualización</div>
                    {(filterProject || filterMacro || filterProcess || filterSearch || filterDocType || filterState || filterAnalyst || externalFilterIds) && <button onClick={clearFilters} className="text-xs text-red-500 hover:text-red-700 flex items-center gap-1 font-medium"><X size={14} /> Limpiar filtros</button>}
                </div>
                {externalFilterIds ? (
                     <div className="bg-blue-50 border border-blue-100 p-3 rounded-lg mb-2 flex justify-between items-center animate-fadeIn">
                        <span className="text-xs text-blue-700 font-semibold">Filtro Activo: Visualizando {externalFilterIds.length} documentos específicos desde reportes.</span>
                        <button onClick={clearFilters} className="text-xs bg-white border border-blue-200 px-2 py-1 rounded text-blue-600">Mostrar Todo</button>
                     </div>
                ) : (
                    <div className="flex flex-wrap gap-2">
                        <select value={filterProject} onChange={(e) => setFilterProject(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-28">
                            <option value="">PROYECTO</option>
                            {availableProjects.map(p => <option key={p} value={p}>{p}</option>)}
                        </select>
                        <select value={filterMacro} onChange={(e) => setFilterMacro(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-32">
                            <option value="">MACROPROCESO</option>
                            {availableMacros.map(m => <option key={m} value={m}>{m}</option>)}
                        </select>
                        <select value={filterProcess} onChange={(e) => setFilterProcess(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-32">
                            <option value="">PROCESO</option>
                            {availableProcesses.map(p => <option key={p} value={p}>{p}</option>)}
                        </select>
                        <div className="relative w-36">
                            <Search size={12} className="absolute left-2 top-1/2 -translate-y-1/2 text-slate-400" />
                            <input type="text" value={filterSearch} onChange={(e) => setFilterSearch(e.target.value)} placeholder="BUSCAR..." className="w-full text-[11px] pl-7 p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none" />
                        </div>
                        <select value={filterDocType} onChange={(e) => setFilterDocType(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-24">
                            <option value="">DOC</option>
                            <option value="AS IS">AS IS</option><option value="FCE">FCE</option><option value="PM">PM</option><option value="TO BE">TO BE</option>
                        </select>
                        <select value={filterState} onChange={(e) => setFilterState(e.target.value)} className="text-[11px] p-2 border border-slate-200 rounded-md bg-slate-50 text-slate-600 outline-none w-24">
                            <option value="">ESTADO</option>
                            {Object.entries(STATE_CONFIG).map(([key, cfg]) => <option key={key} value={key}>{cfg.label.split('(')[0]}</option>)}
                        </select>
                        {!isGuest && (
                          <select value={filterAnalyst} onChange={(e) => setFilterAnalyst(e.target.value)} className="text-[11px] p-2 border border-slate-300 rounded-md bg-slate-50 text-slate-600 outline-none w-32">
                              <option value="">ANALISTA</option>
                              {allUsers.filter(u => u.role === UserRole.ANALYST).map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                          </select>
                        )}
                    </div>
                )}
            </div>

            <div className="overflow-x-auto flex-1">
                <table className="w-full text-[11px] text-left">
                    <thead className="text-[10px] text-slate-400 uppercase font-bold bg-white border-b border-slate-100">
                        <tr>
                            <th className="px-4 py-3 cursor-pointer group" onClick={() => handleSort('project')}>PROYECTO <SortIcon column="project"/></th>
                            <th className="px-4 py-3">JERARQUÍA (MACRO / PROCESO)</th>
                            <th className="px-4 py-3 cursor-pointer group" onClick={() => handleSort('microprocess')}>MICROPROCESO <SortIcon column="microprocess"/></th>
                            <th className="px-4 py-3">DOCUMENTO</th>
                            <th className="px-4 py-3 cursor-pointer group" onClick={() => handleSort('state')}>ESTADO ACTUAL <SortIcon column="state"/></th>
                            <th className="px-4 py-3 text-right cursor-pointer group" onClick={() => handleSort('updatedAt')}>ÚLTIMA ACTIVIDAD <SortIcon column="updatedAt"/></th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-50">
                        {paginatedDocs.length === 0 ? (
                            <tr><td colSpan={6} className="p-12 text-center text-slate-400"><Search size={40} className="mx-auto mb-2 opacity-20"/><p>Sin resultados.</p></td></tr>
                        ) : paginatedDocs.map((doc, idx) => (
                            <tr key={`${doc.id}-${idx}`} className={`transition-colors ${!doc.isRequired ? 'bg-gray-100 hover:bg-gray-200' : 'hover:bg-slate-50'}`}>
                                <td className={`px-4 py-3 font-bold align-top ${!doc.isRequired ? 'text-gray-500' : 'text-slate-700'}`}>{doc.project}</td>
                                <td className="px-4 py-3 align-top">
                                    <div className={`font-bold ${!doc.isRequired ? 'text-gray-500' : 'text-slate-700'}`}>{doc.macroprocess}</div>
                                    <div className="text-slate-500 text-[10px]">{doc.process}</div>
                                </td>
                                <td className="px-4 py-3 align-top">
                                    <div className={`font-bold mb-1 ${!doc.isRequired ? 'text-gray-600' : 'text-slate-800'}`}>{doc.microprocess}</div>
                                    <div className="flex items-center gap-1 text-slate-400" title="Analista Asignado">
                                        <UserIcon size={10} /> <span className="text-[10px] truncate max-w-[120px]">{doc.assignees && doc.assignees.length > 0 ? getUserName(doc.assignees[0]) : 'Sin Asignar'}</span>
                                    </div>
                                </td>
                                <td className="px-4 py-3 align-top">
                                    <span className={`inline-block px-1.5 py-0.5 rounded border text-[10px] font-bold mb-1 ${!doc.isRequired ? 'bg-gray-200 text-gray-400 border-gray-300' : 'bg-indigo-50 text-indigo-700 border-indigo-100'}`}>{doc.docType}</span>
                                    <Link to={`/doc/${doc.id}`} state={{ docData: doc }} className="flex items-center gap-1 text-[10px] font-bold text-indigo-500 hover:text-indigo-700 underline">Ver Detalle</Link>
                                </td>
                                <td className="px-4 py-3 align-top">
                                    <div className={`inline-block px-2 py-0.5 rounded-full text-[10px] font-bold mb-1 border ${!doc.isRequired ? 'bg-gray-200 text-gray-500 border-gray-300' : STATE_CONFIG[doc.state].color}`}>{STATE_CONFIG[doc.state].label.split('(')[0]}</div>
                                    <div className="text-[10px] font-mono text-slate-500">
                                        {formatVersionForDisplay(doc.version)} ({STATE_CONFIG[doc.state].progress}%)
                                    </div>
                                </td>
                                <td className="px-4 py-3 align-top text-right">
                                    {doc.state !== DocState.NOT_STARTED ? (
                                        <div className="text-slate-600 font-medium">{new Date(doc.updatedAt).toLocaleDateString()}</div>
                                    ) : <span className="text-slate-300">-</span>}
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>

            {totalItems > 0 && (
                <div className="px-4 py-3 border-t border-slate-100 bg-slate-50/50 flex flex-col sm:flex-row items-center justify-between gap-4">
                    <div className="text-[11px] text-slate-500">Mostrando <b>{Math.min(totalItems, (currentPage - 1) * ITEMS_PER_PAGE + 1)}</b> a <b>{Math.min(totalItems, currentPage * ITEMS_PER_PAGE)}</b> de <b>{totalItems}</b> registros</div>
                    <div className="flex items-center gap-2">
                        <button onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))} disabled={currentPage === 1} className="p-1.5 rounded-lg border border-slate-200 bg-white hover:bg-slate-50 disabled:opacity-50 transition-all active:scale-95"><ChevronLeft size={16} /></button>
                        <div className="flex items-center gap-1">
                            {visiblePageNumbers.map((pageNum) => (
                                <button 
                                    key={pageNum} 
                                    onClick={() => setCurrentPage(pageNum)} 
                                    className={`w-7 h-7 rounded-lg text-xs font-bold border transition-all ${currentPage === pageNum ? 'bg-indigo-600 text-white border-indigo-600 shadow-sm' : 'bg-white text-slate-600 border-slate-200 hover:border-indigo-400'}`}
                                >
                                    {pageNum}
                                </button>
                            ))}
                        </div>
                        <button onClick={() => setCurrentPage(prev => Math.min(totalPages, prev + 1))} disabled={currentPage === totalPages} className="p-1.5 rounded-lg border border-slate-200 bg-white hover:bg-slate-50 disabled:opacity-50 transition-all active:scale-95"><ChevronRight size={16} /></button>
                    </div>
                </div>
            )}
        </div>

        <div className="lg:col-span-1 space-y-6">
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-4 min-h-[250px] flex flex-col items-center justify-center">
                <h3 className="font-bold text-center mb-2 text-slate-700 text-xs uppercase">Estado Universo Requerido</h3>
                {chartData.length > 0 ? (
                    <div className="h-44 w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <PieChart>
                                <Pie data={chartData} cx="50%" cy="50%" innerRadius={45} outerRadius={65} paddingAngle={2} dataKey="value">
                                    {chartData.map((e, i) => <Cell key={i} fill={e.color}/>)}
                                </Pie>
                                <Tooltip contentStyle={{fontSize: '11px', borderRadius: '8px'}}/>
                            </PieChart>
                        </ResponsiveContainer>
                    </div>
                ) : <p className="text-center text-slate-400 text-[10px]">Sin datos.</p>}
                <div className="flex flex-wrap justify-center gap-x-3 gap-y-1 mt-2">
                    {chartData.map((d, i) => (
                        <div key={i} className="flex items-center gap-1"><span className="w-2 h-2 rounded-full" style={{backgroundColor: d.color}}></span><span className="text-[9px] text-slate-500 uppercase font-bold">{d.name}</span></div>
                    ))}
                </div>
            </div>
            <div className="bg-indigo-50 rounded-xl shadow-sm border border-indigo-100 p-4">
                <h3 className="font-bold text-indigo-900 text-xs uppercase mb-3">Resumen de Cumplimiento</h3>
                <ul className="space-y-2 text-[11px]">
                    <li className="flex justify-between text-slate-600"><span>No Iniciados:</span> <b>{docStats.notStarted}</b></li>
                    <li className="flex justify-between text-blue-600"><span>En Proceso:</span> <b>{docStats.inProcess}</b></li>
                    <li className="flex justify-between text-purple-600"><span>Referente:</span> <b>{docStats.referent}</b></li>
                    <li className="flex justify-between text-orange-600"><span>Control Gestión:</span> <b>{docStats.control}</b></li>
                    <li className="border-t border-indigo-200 pt-1 flex justify-between text-green-600 font-bold"><span>Terminados:</span> <span>{docStats.finished}</span></li>
                </ul>
                <div className="mt-4 pt-3 border-t border-indigo-200 text-[9px] text-slate-500 flex items-center gap-2"><Archive size={12} /><span>Registros en <b>GRIS</b> son históricos externos.</span></div>
            </div>
        </div>
      </div>
    </div>
  );
};

const StatCard = ({ title, value, icon: Icon, color, isActive, onClick, isClickable = true }: any) => (
    <div 
        onClick={isClickable ? onClick : undefined} 
        className={`p-3 rounded-xl shadow-sm border flex items-center space-x-3 transition-all 
            ${isClickable ? 'cursor-pointer hover:border-indigo-300' : 'cursor-default'} 
            ${isActive ? 'ring-2 ring-indigo-300 scale-105' : ''} 
            ${color} border-transparent`}
    >
        <div className="p-1.5 bg-white/50 rounded-lg shrink-0"><Icon size={18}/></div>
        <div className="min-w-0">
            <p className="text-[9px] uppercase font-bold opacity-70 truncate">{title}</p>
            <p className="text-lg font-bold leading-none">{value}</p>
        </div>
    </div>
);

export default Dashboard;

import React from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import Layout from './components/Layout';
import Login from './views/Login';
import Dashboard from './views/Dashboard';
import CreateDocument from './views/CreateDocument';
import DocumentDetail from './views/DocumentDetail';
import AdminUsers from './views/AdminUsers';
import AdminAssignments from './views/AdminAssignments';
import AdminHierarchy from './views/AdminHierarchy'; 
import AdminDatabase from './views/AdminDatabase';
import AdminReferents from './views/AdminReferents';
import AdminGantt from './views/AdminGantt';
import Reports from './views/Reports'; 
import Buffer from './views/Buffer';
import WorkList from './views/WorkList';
import Profile from './views/Profile';
import ManualAnalista from './views/ManualAnalista';
import { UserRole } from './types'; 
import { logoutUser } from './services/firebaseAuthService'; 
import { useAuthStatus } from './hooks/useAuthStatus'; 
import { RefreshCw } from 'lucide-react';

const App: React.FC = () => {
    const { user, cargando } = useAuthStatus(); 

    const handleLogout = async () => {
        await logoutUser(); 
    };

    if (cargando) {
        return (
            <div className="flex flex-col h-screen items-center justify-center bg-slate-50 gap-4">
                <div className="flex items-center gap-2 text-indigo-600 font-semibold animate-pulse">
                    <RefreshCw className="animate-spin" />
                    Cargando aplicación...
                </div>
            </div>
        );
    }

    return (
        <HashRouter>
            <Routes>
                <Route path="/login" element={!user ? <Login /> : <Navigate to="/" />} />
                <Route
                    path="*"
                    element={
                        user ? (
                            <Layout user={user} onLogout={handleLogout}>
                                <Routes>
                                    <Route path="/" element={<Dashboard user={user} />} />
                                    <Route path="/inbox" element={<Buffer user={user} />} />
                                    <Route path="/worklist" element={<WorkList user={user} />} />
                                    <Route path="/new" element={<CreateDocument user={user} />} />
                                    <Route path="/doc/:id" element={<DocumentDetail user={user} />} />
                                    <Route path="/profile" element={<Profile user={user} onUpdate={() => window.location.reload()} />} /> 
                                    <Route path="/manual" element={<ManualAnalista />} />

                                    <Route 
                                        path="/admin/referents" 
                                        element={(user.role === UserRole.ADMIN || user.role === UserRole.COORDINATOR || (user.role === UserRole.ANALYST && user.canAccessReferents)) 
                                            ? <AdminReferents user={user} /> 
                                            : <Navigate to="/" />} 
                                    />
                                    <Route 
                                        path="/admin/reports" 
                                        element={(user.role === UserRole.ADMIN || user.role === UserRole.COORDINATOR || ((user.role === UserRole.ANALYST || user.role === UserRole.GUEST) && user.canAccessReports)) 
                                            ? <Reports user={user} /> 
                                            : <Navigate to="/" />} 
                                    />
                                    <Route 
                                        path="/admin/gantt" 
                                        element={(user.role === UserRole.ADMIN || user.role === UserRole.COORDINATOR || ((user.role === UserRole.ANALYST || user.role === UserRole.GUEST) && user.canAccessGantt)) 
                                            ? <AdminGantt user={user} /> 
                                            : <Navigate to="/" />} 
                                    />

                                    {(user.role === UserRole.ADMIN || user.role === UserRole.COORDINATOR) && (
                                      <>
                                        <Route path="/admin/structure" element={<AdminHierarchy user={user} />} />
                                        <Route path="/admin/assignments" element={<AdminAssignments user={user} />} />
                                      </>
                                    )}

                                    {user.role === UserRole.ADMIN && (
                                        <>
                                            <Route path="/admin/users" element={<AdminUsers />} />
                                            <Route path="/admin/database" element={<AdminDatabase />} />
                                        </>
                                    )}
                                    <Route path="*" element={<Navigate to="/" />} />
                                </Routes>
                            </Layout>
                        ) : (
                            <Navigate to="/login" />
                        )
                    }
                />
            </Routes>
        </HashRouter>
    );
};

export default App;
